     5→/// Scope that provides accessibility-related context to descendants.
     6→///
     7→/// Wrap your app (or a subtree) with this widget to enable [OiA11y]
     8→/// utility methods. [OiApp] includes this automatically.
     9→///
    10→/// {@category Foundation}
    11→class OiA11yScope extends InheritedWidget {
    12→  /// Creates an [OiA11yScope].
    13→  const OiA11yScope({required super.child, super.key});
    14→
    15→  @override
    16→  bool updateShouldNotify(OiA11yScope oldWidget) => false;
    17→}
    18→
    19→/// Accessibility utilities for the obers_ui design system.
    20→///
    21→/// All methods are static and read from [BuildContext] when they need
    22→/// platform/media information.
    23→///
    24→/// {@category Foundation}
    25→abstract final class OiA11y {
    26→  // Private constructor intentionally unreachable; class is static-only.
    27→  // ignore: unused_element
    28→  OiA11y._();
    29→
    30→  /// The minimum touch target size in logical pixels on touch devices.
    31→  ///
    32→  /// Returns 48.0 on touch/mobile, 0.0 on pointer/desktop (no enforcement).
    33→  static double minTouchTarget(BuildContext context) {
    34→    if (kIsWeb) return 0;
    35→    switch (defaultTargetPlatform) {
    36→      case TargetPlatform.iOS:
    37→      case TargetPlatform.android:
    38→        return 48;
    39→      case TargetPlatform.macOS:
    40→      case TargetPlatform.windows:
    41→      case TargetPlatform.linux:
    42→      case TargetPlatform.fuchsia:
    43→        return 0;
    44→    }
    45→  }
    46→
    47→  /// Announces [message] to screen readers.
    48→  ///
    49→  /// When [assertive] is true, the announcement interrupts the screen
    50→  /// reader immediately (use for errors and urgent updates).
    51→  static void announce(
    52→    BuildContext context,
    53→    String message, {
    54→    bool assertive = false,
    55→  }) {
    56→    SemanticsService.sendAnnouncement(
    57→      View.of(context),
    58→      message,
    59→      TextDirection.ltr,
    60→      assertiveness: assertive ? Assertiveness.assertive : Assertiveness.polite,
    61→    );
    62→  }
    63→
    64→  /// Whether the user has requested reduced motion.
    65→  ///
    66→  /// When true, animations should be suppressed or shortened.
    67→  static bool reducedMotion(BuildContext context) {
    68→    return MediaQuery.disableAnimationsOf(context);
    69→  }
    70→
    71→  /// Whether the user has requested high-contrast mode.
    72→  static bool highContrast(BuildContext context) {
    73→    return MediaQuery.highContrastOf(context);
    74→  }
    75→
    76→  /// The current text scale factor.
    77→  static double textScale(BuildContext context) {
    78→    return MediaQuery.textScalerOf(context).scale(1);
    79→  }
    80→
    81→  /// Whether the user has requested bold text.
    82→  static bool boldText(BuildContext context) {
    83→    return MediaQuery.boldTextOf(context);
    84→  }
    85→}
