    13→/// Provides an [OiThemeData] to all descendant widgets.
    14→///
    15→/// Place this widget near the top of the widget tree (e.g. inside [OiApp])
    16→/// and access the theme from any descendant via [OiTheme.of] or the
    17→/// [BuildContext] extension [OiBuildContextThemeExt].
    18→///
    19→/// To override the theme for a subtree, use [OiThemeScope].
    20→///
    21→/// {@category Foundation}
    22→class OiTheme extends InheritedWidget {
    23→  /// Creates an [OiTheme] that provides [data] to all descendants.
    24→  const OiTheme({required this.data, required super.child, super.key});
    25→
    26→  /// The theme data to inject into the subtree.
    27→  final OiThemeData data;
    28→
    29→  /// Returns the nearest [OiThemeData] from the widget tree.
    30→  ///
    31→  /// Throws a [FlutterError] if no [OiTheme] ancestor is found.
    32→  /// Use [maybeOf] for a nullable fallback.
    33→  static OiThemeData of(BuildContext context) {
    34→    final theme = maybeOf(context);
    35→    assert(
    36→      theme != null,
    37→      'No OiTheme found in the widget tree. '
    38→      'Ensure that OiApp or OiTheme wraps your widget.',
    39→    );
    40→    return theme!;
    41→  }
    42→
    43→  /// Returns the nearest [OiThemeData], or null if none is found.
    44→  static OiThemeData? maybeOf(BuildContext context) {
    45→    return context.dependOnInheritedWidgetOfExactType<OiTheme>()?.data;
    46→  }
    47→
    48→  @override
    49→  bool updateShouldNotify(OiTheme oldWidget) => data != oldWidget.data;
    50→}
    51→
    52→/// Scopes an [OiThemeData] override to a subtree.
    53→///
    54→/// Use this to provide a different theme to a specific part of your UI
    55→/// without changing the global theme.
    56→///
    57→/// ```dart
    58→/// OiThemeScope(
    59→///   data: OiTheme.of(context).copyWith(
    60→///     colors: customColors,
    61→///   ),
    62→///   child: MyWidget(),
    63→/// )
    64→/// ```
    65→///
    66→/// {@category Foundation}
    67→class OiThemeScope extends StatelessWidget {
    68→  /// Creates an [OiThemeScope] that overrides the theme for [child].
    69→  const OiThemeScope({required this.data, required this.child, super.key});
    70→
    71→  /// The overriding theme data.
    72→  final OiThemeData data;
    73→
    74→  /// The subtree to receive the overridden theme.
    75→  final Widget child;
    76→
    77→  @override
    78→  Widget build(BuildContext context) {
    79→    return OiTheme(data: data, child: child);
    80→  }
    81→}
    82→
    83→/// Extensions on [BuildContext] for convenient access to [OiThemeData].
    84→///
    85→/// All getters assert that an [OiTheme] ancestor exists in the widget tree.
    86→///
    87→/// {@category Foundation}
    88→extension OiBuildContextThemeExt on BuildContext {
    89→  /// The full [OiThemeData] from the nearest [OiTheme].
