     8→/// Returns all `.dart` files under [dir] recursively.
     9→List<File> _dartFiles(Directory dir) {
    10→  return dir
    11→      .listSync(recursive: true)
    12→      .whereType<File>()
    13→      .where((f) => f.path.endsWith('.dart'))
    14→      .toList();
    15→}
    16→
    17→void main() {
    18→  group('Naming conventions – boolean parameters', () {
    19→    // Matches public `final bool isXxx` or `final bool hasXxx` field
    20→    // declarations in class bodies (also catches required named params that
    21→    // appear as field declarations).
    22→    final badBoolPattern = RegExp(
    23→      r'^\s*(?:required\s+)?(?:final\s+)?bool\s+(is[A-Z]|has[A-Z])',
    24→      multiLine: true,
    25→    );
    26→
    27→    // Matches public constructor parameter patterns like
    28→    //   `required this.isXxx` / `required this.hasXxx`
    29→    //   `this.isXxx` / `this.hasXxx`
    30→    final badCtorParamPattern = RegExp(
    31→      r'\bthis\.(is[A-Z][a-zA-Z0-9]*|has[A-Z][a-zA-Z0-9]*)\b',
    32→    );
    33→
    34→    final libDir = Directory('lib/src');
    35→
    36→    test('no public bool field is prefixed with "is" or "has"', () {
    37→      final violations = <String>[];
    38→
    39→      for (final file in _dartFiles(libDir)) {
    40→        final content = file.readAsStringSync();
    41→        final matches = badBoolPattern.allMatches(content);
    42→        for (final m in matches) {
    43→          final line = content.substring(0, m.start).split('\n').length;
    44→          violations.add('${file.path}:$line — ${m.group(0)?.trim()}');
    45→        }
    46→      }
    47→
    48→      expect(
    49→        violations,
    50→        isEmpty,
    51→        reason:
    52→            'Boolean parameters must use descriptive adjective names (e.g. '
    53→            '"enabled", "loading", "moreAvailable") instead of is/has-prefixed '
    54→            'names. Violations:\n${violations.join('\n')}',
    55→      );
    56→    });
    57→
    58→    test('no constructor parameter uses this.isXxx or this.hasXxx', () {
    59→      final violations = <String>[];
    60→
    61→      for (final file in _dartFiles(libDir)) {
    62→        final content = file.readAsStringSync();
    63→        final lines = content.split('\n');
    64→        for (var i = 0; i < lines.length; i++) {
    65→          if (badCtorParamPattern.hasMatch(lines[i])) {
    66→            violations.add('${file.path}:${i + 1} — ${lines[i].trim()}');
    67→          }
    68→        }
    69→      }
    70→
    71→      expect(
    72→        violations,
    73→        isEmpty,
    74→        reason:
    75→            'Constructor parameters must not use is/has-prefixed boolean '
    76→            'names. Violations:\n${violations.join('\n')}',
    77→      );
    78→    });
    79→  });
    80→}
