     8→/// {@category Foundation}
     9→@immutable
    10→class OiPlatformData {
    11→  /// Creates an [OiPlatformData].
    12→  const OiPlatformData({
    13→    required this.platform,
    14→    required this.keyboardHeight,
    15→    required this.keyboardVisible,
    16→  });
    17→
    18→  /// The host platform.
    19→  final TargetPlatform platform;
    20→
    21→  /// The height of the on-screen keyboard in logical pixels.
    22→  ///
    23→  /// Sourced from [MediaQueryData.viewInsets.bottom].
    24→  final double keyboardHeight;
    25→
    26→  /// Whether the on-screen keyboard is currently visible.
    27→  ///
    28→  /// True when [keyboardHeight] is greater than zero.
    29→  final bool keyboardVisible;
    30→
    31→  @override
    32→  bool operator ==(Object other) {
    33→    if (identical(this, other)) return true;
    34→    return other is OiPlatformData &&
    35→        other.platform == platform &&
    36→        other.keyboardHeight == keyboardHeight &&
    37→        other.keyboardVisible == keyboardVisible;
    38→  }
    39→
    40→  @override
    41→  int get hashCode => Object.hash(platform, keyboardHeight, keyboardVisible);
    42→
    43→  @override
    44→  String toString() =>
    45→      'OiPlatformData(platform: $platform, keyboardHeight: $keyboardHeight, '
    46→      'keyboardVisible: $keyboardVisible)';
    47→}
    48→
    49→/// An [InheritedWidget] that provides [OiPlatformData] to its descendants.
    50→///
    51→/// Wrap your app root (or any subtree) with [OiPlatform] to expose
    52→/// platform context. [OiApp] includes this automatically.
    53→///
    54→/// {@category Foundation}
    55→class OiPlatform extends InheritedWidget {
    56→  /// Creates an [OiPlatform] with explicit [data].
    57→  const OiPlatform({required this.data, required super.child, super.key});
    58→
    59→  /// Creates an [OiPlatform] that derives its data from [MediaQuery].
    60→  ///
    61→  /// [platform] defaults to [defaultTargetPlatform].
    62→  factory OiPlatform.fromContext({
    63→    required BuildContext context,
    64→    required Widget child,
    65→    TargetPlatform? platform,
    66→    Key? key,
    67→  }) {
    68→    final insets = MediaQuery.viewInsetsOf(context);
    69→    final keyboardHeight = insets.bottom;
    70→    return OiPlatform(
    71→      key: key,
    72→      data: OiPlatformData(
    73→        platform: platform ?? defaultTargetPlatform,
    74→        keyboardHeight: keyboardHeight,
    75→        keyboardVisible: keyboardHeight > 0,
    76→      ),
    77→      child: child,
    78→    );
    79→  }
    80→
    81→  /// The platform data available to descendants.
    82→  final OiPlatformData data;
    83→
    84→  /// Returns the nearest [OiPlatformData] from [context].
    85→  ///
    86→  /// Asserts that an [OiPlatform] exists in the widget tree.
    87→  static OiPlatformData of(BuildContext context) {
    88→    final result = context.dependOnInheritedWidgetOfExactType<OiPlatform>();
    89→    assert(result != null, 'No OiPlatform found in context');
    90→    return result!.data;
    91→  }
    92→
    93→  /// Returns the nearest [OiPlatformData] from [context], or null if none.
    94→  static OiPlatformData? maybeOf(BuildContext context) {
    95→    return context.dependOnInheritedWidgetOfExactType<OiPlatform>()?.data;
    96→  }
    97→
    98→  @override
    99→  bool updateShouldNotify(OiPlatform oldWidget) => data != oldWidget.data;
   100→}
   101→
   102→/// Extensions on [BuildContext] for convenient platform access.
   103→///
   104→/// {@category Foundation}
   105→extension OiPlatformExt on BuildContext {
   106→  /// The nearest [OiPlatformData] from this context.
   107→  ///
   108→  /// Asserts that an [OiPlatform] exists in the widget tree.
   109→  OiPlatformData get platform => OiPlatform.of(this);
