     3→/// A breakpoint defined by a minimum viewport width.
     4→///
     5→/// The design system ships five standard breakpoints as static constants.
     6→/// Custom breakpoints can be created with the default constructor.
     7→///
     8→/// {@category Foundation}
     9→@immutable
    10→class OiBreakpoint implements Comparable<OiBreakpoint> {
    11→  /// Creates a custom breakpoint with a [name] and [minWidth].
    12→  const OiBreakpoint(this.name, this.minWidth)
    13→    : assert(minWidth >= 0, 'minWidth must be >= 0');
    14→
    15→  /// Compact — phones in portrait (<600dp).
    16→  static const OiBreakpoint compact = OiBreakpoint('compact', 0);
    17→
    18→  /// Medium — large phones / small tablets (600–840dp).
    19→  static const OiBreakpoint medium = OiBreakpoint('medium', 600);
    20→
    21→  /// Expanded — tablets and small desktops (840–1200dp).
    22→  static const OiBreakpoint expanded = OiBreakpoint('expanded', 840);
    23→
    24→  /// Large — large desktop monitors (1200–1600dp).
    25→  static const OiBreakpoint large = OiBreakpoint('large', 1200);
    26→
    27→  /// Extra-large — ultra-wide monitors (>1600dp).
    28→  static const OiBreakpoint extraLarge = OiBreakpoint('extraLarge', 1600);
    29→
    30→  /// All standard breakpoints in ascending order.
    31→  static const List<OiBreakpoint> values = [
    32→    compact,
    33→    medium,
    34→    expanded,
    35→    large,
    36→    extraLarge,
    37→  ];
    38→
    39→  /// The human-readable name of this breakpoint.
    40→  final String name;
    41→
    42→  /// The minimum viewport width in logical pixels at which this breakpoint
    43→  /// activates.
    44→  final double minWidth;
    45→
    46→  @override
    47→  int compareTo(OiBreakpoint other) => minWidth.compareTo(other.minWidth);
    48→
    49→  /// Whether [width] falls within this breakpoint's range.
    50→  bool matches(double width) => width >= minWidth;
    51→
    52→  @override
    53→  bool operator ==(Object other) {
    54→    if (identical(this, other)) return true;
    55→    return other is OiBreakpoint &&
    56→        other.name == name &&
    57→        other.minWidth == minWidth;
    58→  }
    59→
    60→  @override
    61→  int get hashCode => Object.hash(name, minWidth);
    62→
    63→  @override
    64→  String toString() => 'OiBreakpoint($name, $minWidth)';
    65→}
    66→
    67→/// Vertical screen height classifications.
    68→///
    69→/// {@category Foundation}
    70→enum OiHeightBreakpoint {
    71→  /// Short screen — typically a phone in landscape (<500dp tall).
    72→  short,
    73→
    74→  /// Regular screen height.
    75→  regular,
    76→
    77→  /// Tall screen — large tablets and desktops (>900dp tall).
    78→  tall,
    79→}
    80→
    81→/// A value that resolves differently at different breakpoints.
    82→///
    83→/// Provide values for any subset of breakpoints. When resolving, the largest
    84→/// breakpoint that does not exceed [width] and has a provided value is used.
    85→/// If no value is found, [fallback] is returned.
    86→///
    87→/// {@category Foundation}
    88→class OiResponsiveValue<T> {
    89→  /// Creates an [OiResponsiveValue] with per-breakpoint values.
    90→  const OiResponsiveValue({
    91→    this.compact,
    92→    this.medium,
    93→    this.expanded,
    94→    this.large,
    95→    this.extraLarge,
    96→    this.fallback,
    97→  });
    98→
    99→  /// Value at the compact breakpoint.
   100→  final T? compact;
   101→
   102→  /// Value at the medium breakpoint.
   103→  final T? medium;
   104→
   105→  /// Value at the expanded breakpoint.
   106→  final T? expanded;
   107→
   108→  /// Value at the large breakpoint.
   109→  final T? large;
   110→
   111→  /// Value at the extra-large breakpoint.
   112→  final T? extraLarge;
   113→
   114→  /// Fallback value when no breakpoint-specific value is defined.
   115→  final T? fallback;
   116→
   117→  /// Resolves the value for the given [width].
   118→  ///
   119→  /// Returns the value for the largest breakpoint that is active (<=width)
   120→  /// and has a non-null value. Falls back to [fallback] if none match.
   121→  T? resolve(double width) {
   122→    if (width >= OiBreakpoint.extraLarge.minWidth && extraLarge != null) {
   123→      return extraLarge;
   124→    }
   125→    if (width >= OiBreakpoint.large.minWidth && large != null) return large;
   126→    if (width >= OiBreakpoint.expanded.minWidth && expanded != null) {
   127→      return expanded;
   128→    }
   129→    if (width >= OiBreakpoint.medium.minWidth && medium != null) return medium;
   130→    if (width >= OiBreakpoint.compact.minWidth && compact != null) {
   131→      return compact;
   132→    }
   133→    return fallback;
   134→  }
   135→}
   136→
   137→/// Extensions on [BuildContext] for responsive layout helpers.
   138→///
   139→/// All getters read the current [MediaQueryData.size] width.
   140→///
   141→/// {@category Foundation}
   142→extension OiResponsiveExt on BuildContext {
   143→  double get _width => MediaQuery.sizeOf(this).width;
   144→  double get _height => MediaQuery.sizeOf(this).height;
   145→
   146→  /// The active [OiBreakpoint] for the current screen width.
   147→  OiBreakpoint get breakpoint {
   148→    final width = _width;
   149→    if (width >= OiBreakpoint.extraLarge.minWidth) {
   150→      return OiBreakpoint.extraLarge;
   151→    }
   152→    if (width >= OiBreakpoint.large.minWidth) return OiBreakpoint.large;
   153→    if (width >= OiBreakpoint.expanded.minWidth) return OiBreakpoint.expanded;
   154→    if (width >= OiBreakpoint.medium.minWidth) return OiBreakpoint.medium;
   155→    return OiBreakpoint.compact;
   156→  }
   157→
   158→  /// Whether the current breakpoint is compact.
   159→  bool get isCompact => _width < OiBreakpoint.medium.minWidth;
   160→
   161→  /// Whether the current breakpoint is medium.
   162→  bool get isMedium =>
   163→      _width >= OiBreakpoint.medium.minWidth &&
   164→      _width < OiBreakpoint.expanded.minWidth;
   165→
   166→  /// Whether the current breakpoint is expanded.
   167→  bool get isExpanded =>
   168→      _width >= OiBreakpoint.expanded.minWidth &&
   169→      _width < OiBreakpoint.large.minWidth;
   170→
   171→  /// Whether the current breakpoint is large.
   172→  bool get isLarge =>
   173→      _width >= OiBreakpoint.large.minWidth &&
   174→      _width < OiBreakpoint.extraLarge.minWidth;
   175→
   176→  /// Whether the current breakpoint is extra-large.
   177→  bool get isExtraLarge => _width >= OiBreakpoint.extraLarge.minWidth;
   178→
   179→  /// Whether the width is at least medium (>=600dp).
   180→  bool get isMediumOrWider => _width >= OiBreakpoint.medium.minWidth;
   181→
   182→  /// Whether the width is at least expanded (>=840dp).
   183→  bool get isExpandedOrWider => _width >= OiBreakpoint.expanded.minWidth;
   184→
   185→  /// Whether the width is at least large (>=1200dp).
   186→  bool get isLargeOrWider => _width >= OiBreakpoint.large.minWidth;
   187→
   188→  /// Resolves an [OiResponsiveValue] for the current screen width.
   189→  T? responsive<T>(OiResponsiveValue<T> value) => value.resolve(_width);
   190→
   191→  /// Returns one of two values based on the current breakpoint.
   192→  ///
   193→  /// [compact] is returned on small screens, [expanded] on larger screens.
   194→  T adaptive<T>({required T compact, required T expanded}) {
   195→    return isExpandedOrWider ? expanded : compact;
   196→  }
   197→
   198→  /// The current screen orientation.
   199→  Orientation get orientation => MediaQuery.orientationOf(this);
   200→
   201→  /// Whether the screen is in portrait orientation.
   202→  bool get isPortrait => orientation == Orientation.portrait;
   203→
   204→  /// Whether the screen is in landscape orientation.
   205→  bool get isLandscape => orientation == Orientation.landscape;
   206→
   207→  /// The current vertical height breakpoint.
   208→  OiHeightBreakpoint get heightBreakpoint {
   209→    if (_height >= 900) return OiHeightBreakpoint.tall;
   210→    if (_height >= 500) return OiHeightBreakpoint.regular;
   211→    return OiHeightBreakpoint.short;
   212→  }
   213→
   214→  /// The recommended page gutter (horizontal padding) for the current
   215→  /// breakpoint.
   216→  double get pageGutter {
   217→    if (isExtraLarge) return 48;
   218→    if (isLargeOrWider) return 40;
   219→    if (isExpandedOrWider) return 32;
   220→    if (isMediumOrWider) return 24;
   221→    return 16;
   222→  }
   223→
   224→  /// The recommended maximum content width for the current breakpoint.
   225→  double get contentMaxWidth {
   226→    if (isExtraLarge) return 1400;
   227→    if (isLargeOrWider) return 1200;
   228→    if (isExpandedOrWider) return 960;
   229→    if (isMediumOrWider) return 720;
   230→    return double.infinity;
   231→  }
   232→}
