    64→/// The overlay management service for the obers_ui design system.
    65→///
    66→/// Shows overlays (dialogs, toasts, panels, etc.) above all other content
    67→/// via [OiOverlays.of]. The service is provided by [OiApp] through
    68→/// [buildOiOverlaysHost].
    69→///
    70→/// {@category Foundation}
    71→class OiOverlaysService {
    72→  OiOverlaysService._();
    73→
    74→  OverlayState? _overlayState;
    75→  final List<OiOverlayHandle> _activeHandles = [];
    76→
    77→  /// Shows a custom overlay widget above all content.
    78→  ///
    79→  /// Returns an [OiOverlayHandle] that can be used to dismiss or update
    80→  /// the overlay.
    81→  OiOverlayHandle show({
    82→    required WidgetBuilder builder,
    83→    OiOverlayZOrder zOrder = OiOverlayZOrder.base,
    84→    bool dismissible = true,
    85→    VoidCallback? onDismiss,
    86→  }) {
    87→    assert(_overlayState != null, 'OiOverlays not attached to OverlayState');
    88→
    89→    late OiOverlayHandle handle;
    90→    late OverlayEntry entry;
    91→
    92→    entry = OverlayEntry(
    93→      builder: (context) {
    94→        if (dismissible) {
    95→          return Stack(
    96→            children: [
    97→              // Invisible dismiss barrier
    98→              Positioned.fill(
    99→                child: GestureDetector(
   100→                  behavior: HitTestBehavior.translucent,
   101→                  onTap: () {
   102→                    onDismiss?.call();
   103→                    handle.dismiss();
   104→                  },
   105→                  child: const SizedBox.expand(),
   106→                ),
   107→              ),
   108→              builder(context),
   109→            ],
   110→          );
   111→        }
   112→        return builder(context);
   113→      },
   114→    );
   115→
   116→    handle = OiOverlayHandle._(entry);
   117→    _activeHandles.add(handle);
   118→    _overlayState!.insert(entry);
   119→
   120→    return handle;
   121→  }
   122→
   123→  /// Dismisses all active overlays.
   124→  void dismissAll() {
   125→    // Copy list to avoid modification during iteration
   126→    for (final h in List<OiOverlayHandle>.of(_activeHandles)) {
   127→      h.dismiss();
   128→    }
   129→    _activeHandles.removeWhere((h) => h.isDismissed);
   130→  }
   131→}
