     3→/// A single undoable action.
     4→///
     5→/// Encapsulates the forward (redo) and backward (undo) operations,
     6→/// plus an optional [merge] function for coalescing rapid consecutive
     7→/// actions of the same type (e.g. typing).
     8→///
     9→/// {@category Foundation}
    10→@immutable
    11→class OiUndoAction {
    12→  /// Creates an [OiUndoAction].
    13→  const OiUndoAction({
    14→    required this.label,
    15→    required this.execute,
    16→    required this.undo,
    17→    this.merge,
    18→    this.groupId,
    19→  });
    20→
    21→  /// Human-readable label for the action (e.g. "Rename column").
    22→  final String label;
    23→
    24→  /// Performs (or re-performs) the action.
    25→  final VoidCallback execute;
    26→
    27→  /// Reverses the action.
    28→  final VoidCallback undo;
    29→
    30→  /// Optional merger — if provided, the undo stack may call this with the
    31→  /// next pushed action to produce a merged action (grouping rapid edits).
    32→  ///
    33→  /// Returns null if the two actions cannot be merged.
    34→  final OiUndoAction? Function(OiUndoAction next)? merge;
    35→
    36→  /// Optional group identifier for merging related actions.
    37→  ///
    38→  /// Actions with the same non-null [groupId] are eligible for merging.
    39→  final String? groupId;
    40→}
    41→
    42→/// A history stack for undo/redo operations.
    43→///
    44→/// Push [OiUndoAction]s when the user performs undoable operations.
    45→/// The stack automatically handles merging of adjacent actions with the
    46→/// same [OiUndoAction.groupId] when a [merge] function is provided.
    47→///
    48→/// Access the stack from the widget tree via [OiUndoStackProvider] and
    49→/// [OiUndoStack.of].
    50→///
    51→/// {@category Foundation}
    52→class OiUndoStack extends ChangeNotifier {
    53→  /// Creates an [OiUndoStack] with an optional history limit.
    54→  OiUndoStack({int maxHistory = 50}) : _maxHistory = maxHistory;
    55→
    56→  final int _maxHistory;
    57→  final List<OiUndoAction> _history = [];
    58→  final List<OiUndoAction> _future = [];
    59→
    60→  /// Whether there are actions available to undo.
    61→  bool get canUndo => _history.isNotEmpty;
    62→
    63→  /// Whether there are actions available to redo.
    64→  bool get canRedo => _future.isNotEmpty;
    65→
    66→  /// The current undo history (oldest first).
    67→  List<OiUndoAction> get history => List.unmodifiable(_history);
    68→
    69→  /// The available redo steps (most-recent-undone first).
    70→  List<OiUndoAction> get future => List.unmodifiable(_future);
    71→
    72→  /// The label of the next action that would be undone, or null.
    73→  String? get nextUndoLabel => _history.isNotEmpty ? _history.last.label : null;
    74→
    75→  /// The label of the next action that would be redone, or null.
    76→  String? get nextRedoLabel => _future.isNotEmpty ? _future.last.label : null;
    77→
    78→  /// Pushes [action] onto the history stack and executes it.
    79→  ///
    80→  /// Clears the redo stack. If the new action can be merged with the
    81→  /// previous one (same [groupId] and a [merge] function), they are
    82→  /// coalesced into one entry.
    83→  void push(OiUndoAction action) {
    84→    // Attempt merge with the most recent history entry
    85→    if (_history.isNotEmpty) {
    86→      final last = _history.last;
    87→      if (last.groupId != null &&
    88→          last.groupId == action.groupId &&
    89→          last.merge != null) {
    90→        final merged = last.merge!(action);
    91→        if (merged != null) {
    92→          _history
    93→            ..removeLast()
    94→            ..add(merged);
    95→          _future.clear();
    96→          notifyListeners();
    97→          return;
    98→        }
    99→      }
   100→    }
   101→
   102→    _history.add(action);
   103→    _future.clear();
   104→
   105→    // Enforce max history limit
   106→    while (_history.length > _maxHistory) {
   107→      _history.removeAt(0);
   108→    }
   109→
   110→    notifyListeners();
   111→  }
   112→
   113→  /// Undoes the most recent action, moving it to the redo stack.
   114→  ///
   115→  /// Does nothing if [canUndo] is false.
   116→  void undo() {
   117→    if (!canUndo) return;
   118→    final action = _history.removeLast();
   119→    action.undo();
   120→    _future.add(action);
   121→    notifyListeners();
   122→  }
   123→
   124→  /// Redoes the most recently undone action.
   125→  ///
   126→  /// Does nothing if [canRedo] is false.
   127→  void redo() {
   128→    if (!canRedo) return;
   129→    final action = _future.removeLast();
   130→    action.execute();
   131→    _history.add(action);
   132→    notifyListeners();
   133→  }
   134→
   135→  /// Clears both the history and future stacks.
   136→  void clear() {
   137→    _history.clear();
   138→    _future.clear();
   139→    notifyListeners();
   140→  }
   141→
   142→  /// Returns the stack from the nearest [OiUndoStackProvider].
   143→  ///
   144→  /// Throws if no [OiUndoStackProvider] is found.
   145→  static OiUndoStack of(BuildContext context) {
   146→    final provider = context
   147→        .dependOnInheritedWidgetOfExactType<OiUndoStackProvider>();
   148→    assert(
   149→      provider != null,
   150→      'No OiUndoStackProvider found in the widget tree.',
   151→    );
   152→    return provider!.stack;
   153→  }
   154→
   155→  /// Returns the stack from the nearest [OiUndoStackProvider], or null.
   156→  static OiUndoStack? maybeOf(BuildContext context) {
   157→    return context
   158→        .dependOnInheritedWidgetOfExactType<OiUndoStackProvider>()
   159→        ?.stack;
   160→  }
   161→}
   162→
   163→/// Provides an [OiUndoStack] to all descendant widgets.
   164→///
   165→/// Typically placed inside [OiApp] to make undo/redo globally available.
   166→///
   167→/// {@category Foundation}
   168→class OiUndoStackProvider extends InheritedNotifier<OiUndoStack> {
   169→  /// Creates an [OiUndoStackProvider] that provides [stack].
   170→  const OiUndoStackProvider({
   171→    required OiUndoStack stack,
   172→    required super.child,
   173→    super.key,
   174→  }) : super(notifier: stack);
   175→
   176→  /// The undo stack made available to descendants.
   177→  OiUndoStack get stack => notifier!;
   178→}
