     7→/// A group of buttons displayed inline with a connected visual appearance.
     8→///
     9→/// Buttons in a group share their borders so that adjacent buttons appear
    10→/// joined together. In [segmented] mode exactly one button is active at a time
    11→/// (the one at [selectedIndex]); tapping any button calls [onSelected] with
    12→/// its index.
    13→///
    14→/// ```dart
    15→/// OiButtonGroup(
    16→///   buttons: [
    17→///     OiButton.outline(label: 'Day'),
    18→///     OiButton.outline(label: 'Week'),
    19→///     OiButton.outline(label: 'Month'),
    20→///   ],
    21→///   segmented: true,
    22→///   selectedIndex: _tab,
    23→///   onSelected: (i) => setState(() => _tab = i),
    24→/// )
    25→/// ```
    26→///
    27→/// {@category Components}
    28→class OiButtonGroup extends StatelessWidget {
    29→  /// Creates an [OiButtonGroup].
    30→  const OiButtonGroup({
    31→    required this.buttons,
    32→    this.orientation = Axis.horizontal,
    33→    this.segmented = false,
    34→    this.selectedIndex,
    35→    this.onSelected,
    36→    super.key,
    37→  });
    38→
    39→  /// The buttons to render inside the group.
    40→  final List<OiButton> buttons;
    41→
    42→  /// Whether buttons are arranged horizontally or vertically.
    43→  final Axis orientation;
    44→
    45→  /// When `true`, tapping a button marks it as selected and calls [onSelected].
    46→  final bool segmented;
    47→
    48→  /// The index of the currently selected button in [segmented] mode.
    49→  final int? selectedIndex;
    50→
    51→  /// Called with the tapped button's index when [segmented] is `true`.
    52→  final ValueChanged<int>? onSelected;
    53→
    54→  @override
    55→  Widget build(BuildContext context) {
    56→    final count = buttons.length;
    57→    if (count == 0) return const SizedBox.shrink();
    58→
    59→    final items = List<Widget>.generate(count, (i) {
    60→      return _GroupButtonItem(
    61→        button: buttons[i],
    62→        index: i,
    63→        count: count,
    64→        orientation: orientation,
    65→        segmented: segmented,
    66→        selected: segmented && selectedIndex == i,
    67→        onSelected: onSelected,
    68→      );
    69→    });
    70→
    71→    if (orientation == Axis.horizontal) {
    72→      return Row(mainAxisSize: MainAxisSize.min, children: items);
    73→    } else {
    74→      return Column(mainAxisSize: MainAxisSize.min, children: items);
    75→    }
    76→  }
    77→}
    78→
    79→// ── Internal per-item widget ──────────────────────────────────────────────
    80→
    81→class _GroupButtonItem extends StatelessWidget {
    82→  const _GroupButtonItem({
    83→    required this.button,
    84→    required this.index,
    85→    required this.count,
    86→    required this.orientation,
    87→    required this.segmented,
    88→    required this.selected,
    89→    required this.onSelected,
    90→  });
    91→
    92→  final OiButton button;
    93→  final int index;
    94→  final int count;
    95→  final Axis orientation;
    96→  final bool segmented;
    97→  final bool selected;
    98→  final ValueChanged<int>? onSelected;
    99→
   100→  @override
   101→  Widget build(BuildContext context) {
   102→    final radius = context.components.button?.borderRadius ?? context.radius.sm;
   103→
   104→    // Compute per-corner radii so the group looks connected.
   105→    final BorderRadius borderRadius;
   106→    if (count == 1) {
   107→      borderRadius = radius;
   108→    } else if (orientation == Axis.horizontal) {
   109→      if (index == 0) {
   110→        borderRadius = BorderRadius.only(
   111→          topLeft: radius.topLeft,
   112→          bottomLeft: radius.bottomLeft,
   113→        );
   114→      } else if (index == count - 1) {
   115→        borderRadius = BorderRadius.only(
   116→          topRight: radius.topRight,
   117→          bottomRight: radius.bottomRight,
   118→        );
   119→      } else {
   120→        borderRadius = BorderRadius.zero;
   121→      }
   122→    } else {
   123→      // vertical
   124→      if (index == 0) {
   125→        borderRadius = BorderRadius.only(
   126→          topLeft: radius.topLeft,
   127→          topRight: radius.topRight,
   128→        );
   129→      } else if (index == count - 1) {
   130→        borderRadius = BorderRadius.only(
   131→          bottomLeft: radius.bottomLeft,
   132→          bottomRight: radius.bottomRight,
   133→        );
   134→      } else {
   135→        borderRadius = BorderRadius.zero;
   136→      }
   137→    }
   138→
   139→    // In segmented mode, selected = primary fill, others = ghost with border.
   140→    final OiButtonVariant effectiveVariant;
   141→    if (segmented) {
   142→      effectiveVariant = selected
   143→          ? OiButtonVariant.primary
   144→          : OiButtonVariant.ghost;
   145→    } else {
   146→      effectiveVariant = button.variant;
   147→    }
   148→
   149→    final bgColor = _bgColor(context, effectiveVariant);
   150→    final fgColor = _fgColor(context, effectiveVariant);
   151→    final density = OiDensityScope.of(context);
   152→    final height = _buttonHeight(density);
   153→    final hPad = _hPadding(context);
   154→
   155→    // Build border: for connected group, share the edge between neighbours.
   156→    final border = _buildBorder(context, effectiveVariant);
   157→
   158→    final content = button.label != null
   159→        ? Text(
   160→            button.label!,
   161→            style: TextStyle(
   162→              fontSize: _fontSize(),
   163→              fontWeight: FontWeight.w500,
   164→              color: fgColor,
   165→              height: 1,
   166→            ),
   167→            maxLines: 1,
   168→            overflow: TextOverflow.ellipsis,
   169→          )
   170→        : (button.icon != null
   171→              ? Icon(button.icon, size: _iconSize(), color: fgColor)
   172→              : const SizedBox.shrink());
   173→
   174→    final isEnabled = button.enabled;
   175→    final tapCallback = segmented
   176→        ? (isEnabled ? () => onSelected?.call(index) : null)
   177→        : (isEnabled ? button.onTap : null);
   178→
   179→    return OiTappable(
   180→      onTap: tapCallback,
   181→      enabled: isEnabled,
   182→      child: Container(
   183→        height: height,
   184→        padding: EdgeInsets.symmetric(horizontal: hPad),
   185→        decoration: BoxDecoration(
   186→          color: bgColor,
   187→          borderRadius: borderRadius,
   188→          border: border,
   189→        ),
   190→        child: Center(child: content),
   191→      ),
   192→    );
   193→  }
   194→
   195→  Color _bgColor(BuildContext context, OiButtonVariant variant) {
   196→    final c = context.colors;
   197→    switch (variant) {
   198→      case OiButtonVariant.primary:
   199→        return c.primary.base;
   200→      case OiButtonVariant.secondary:
   201→        return c.accent.base;
   202→      case OiButtonVariant.outline:
   203→      case OiButtonVariant.ghost:
   204→        return const Color(0x00000000);
   205→      case OiButtonVariant.destructive:
   206→        return c.error.base;
   207→      case OiButtonVariant.soft:
   208→        return c.primary.muted;
   209→    }
   210→  }
   211→
   212→  Color _fgColor(BuildContext context, OiButtonVariant variant) {
   213→    final c = context.colors;
   214→    switch (variant) {
   215→      case OiButtonVariant.primary:
   216→        return c.primary.foreground;
   217→      case OiButtonVariant.secondary:
   218→        return c.accent.foreground;
   219→      case OiButtonVariant.outline:
   220→      case OiButtonVariant.ghost:
   221→        return c.text;
   222→      case OiButtonVariant.destructive:
   223→        return c.error.foreground;
   224→      case OiButtonVariant.soft:
   225→        return c.primary.base;
   226→    }
   227→  }
   228→
   229→  Border? _buildBorder(BuildContext context, OiButtonVariant variant) {
   230→    if (variant != OiButtonVariant.outline &&
   231→        variant != OiButtonVariant.ghost &&
   232→        !segmented) {
   233→      return null;
   234→    }
   235→    final borderColor = context.colors.border;
   236→    final side = BorderSide(color: borderColor);
   237→
   238→    if (count == 1) {
   239→      return Border.all(color: borderColor);
   240→    }
   241→
   242→    if (orientation == Axis.horizontal) {
   243→      // For horizontal groups: left border only on first, right border on last,
   244→      // internal items share a border so we only draw left for non-first.
