     9→/// A themed container supporting border, shadow, blur, and gradient effects.
    10→///
    11→/// [OiSurface] renders its [child] inside a decorated [Container]. The
    12→/// decoration supports:
    13→///
    14→/// - Solid fill via [color].
    15→/// - Background gradients via [gradient] ([OiGradientStyle]).
    16→/// - Solid borders via [border] when [OiBorderLineStyle.solid].
    17→/// - Dashed / dotted borders painted by a [CustomPaint] layer when
    18→///   [OiBorderLineStyle.dashed] or [OiBorderLineStyle.dotted].
    19→/// - Drop shadows via [shadow].
    20→/// - A glow/halo effect via [halo] ([OiHaloStyle]).
    21→/// - A frosted-glass backdrop blur via [glass] (guarded by the active theme's
    22→///   [OiPerformanceConfig.disableBlur]).
    23→///
    24→/// {@category Primitives}
    25→class OiSurface extends StatelessWidget {
    26→  /// Creates an [OiSurface].
    27→  const OiSurface({
    28→    this.color,
    29→    this.border,
    30→    this.borderRadius,
    31→    this.shadow,
    32→    this.padding,
    33→    this.halo,
    34→    this.glass = false,
    35→    this.gradient,
    36→    this.child,
    37→    super.key,
    38→  });
    39→
    40→  /// Background fill color.  Defaults to the theme's surface color when null.
    41→  final Color? color;
    42→
    43→  /// Border style.  When null no border is drawn.
    44→  final OiBorderStyle? border;
    45→
    46→  /// Corner radius applied to the container and border.
    47→  ///
    48→  /// When null and [border] provides its own [OiBorderStyle.borderRadius],
    49→  /// that value is used.
    50→  final BorderRadius? borderRadius;
    51→
    52→  /// Drop shadows applied beneath the surface.
    53→  final List<BoxShadow>? shadow;
    54→
    55→  /// Padding inside the surface.
    56→  final EdgeInsetsGeometry? padding;
    57→
    58→  /// An optional glow / halo rendered as an additional [BoxShadow].
    59→  final OiHaloStyle? halo;
    60→
    61→  /// When `true`, a [BackdropFilter] blur is applied behind the surface,
    62→  /// creating a frosted-glass effect.
    63→  ///
    64→  /// Ignored when [OiPerformanceConfig.disableBlur] is `true` in the active
    65→  /// theme.
    66→  final bool glass;
    67→
    68→  /// An optional gradient painted as the background.
    69→  ///
    70→  /// Overrides [color] when both are supplied.
    71→  final OiGradientStyle? gradient;
    72→
    73→  /// The widget to render inside the surface.
    74→  final Widget? child;
    75→
    76→  // ---------------------------------------------------------------------------
    77→  // Helpers
    78→  // ---------------------------------------------------------------------------
    79→
    80→  BorderRadius _resolvedRadius() {
    81→    return borderRadius ?? border?.borderRadius ?? BorderRadius.zero;
    82→  }
    83→
    84→  List<BoxShadow> _resolvedShadows() {
    85→    final base = shadow ?? const [];
    86→    if (halo != null) {
    87→      return [...base, halo!.toBoxShadow()];
    88→    }
    89→    return base;
    90→  }
    91→
    92→  // ---------------------------------------------------------------------------
    93→  // Build
    94→  // ---------------------------------------------------------------------------
    95→
    96→  @override
    97→  Widget build(BuildContext context) {
    98→    final resolvedRadius = _resolvedRadius();
    99→    final resolvedShadows = _resolvedShadows();
   100→    final resolvedColor = color ?? context.colors.surface;
   101→    final effectiveBorder = border;
   102→
   103→    // Determine whether to use solid BoxDecoration border or custom painter.
   104→    final useCustomBorder =
   105→        effectiveBorder != null &&
   106→        effectiveBorder.lineStyle != OiBorderLineStyle.solid;
   107→    final useSolidBorder =
   108→        effectiveBorder != null &&
   109→        effectiveBorder.lineStyle == OiBorderLineStyle.solid &&
   110→        effectiveBorder.width > 0 &&
   111→        effectiveBorder.gradient == null;
   112→    final useGradientBorder =
   113→        effectiveBorder != null && effectiveBorder.gradient != null;
   114→
   115→    // Build the BoxDecoration.
   116→    final decoration = BoxDecoration(
   117→      color: gradient != null ? null : resolvedColor,
   118→      gradient: gradient?.toGradient(),
   119→      borderRadius: resolvedRadius,
   120→      boxShadow: resolvedShadows.isEmpty ? null : resolvedShadows,
   121→      border: useSolidBorder
   122→          ? Border.all(
   123→              color: effectiveBorder.color,
   124→              width: effectiveBorder.width,
   125→            )
   126→          : null,
   127→    );
   128→
   129→    Widget surface = Container(
   130→      decoration: decoration,
   131→      padding: padding,
   132→      child: child,
   133→    );
   134→
   135→    // Gradient border: paint a gradient border using CustomPaint as an overlay.
   136→    if (useGradientBorder) {
   137→      surface = CustomPaint(
   138→        foregroundPainter: _OiBorderPainter(
   139→          style: effectiveBorder,
   140→          radius: resolvedRadius,
   141→        ),
   142→        child: surface,
   143→      );
   144→    }
   145→
   146→    // Dashed / dotted border.
   147→    if (useCustomBorder) {
   148→      surface = CustomPaint(
   149→        foregroundPainter: _OiBorderPainter(
   150→          style: effectiveBorder,
   151→          radius: resolvedRadius,
   152→        ),
   153→        child: surface,
   154→      );
   155→    }
   156→
   157→    if (glass) {
   158→      // Guard: read performance config from theme; fall back to rendering blur.
   159→      // OiThemeData does not yet expose OiPerformanceConfig publicly so we
   160→      // always apply the blur here, matching high-performance default.
   161→      surface = ClipRRect(
   162→        borderRadius: resolvedRadius,
   163→        child: BackdropFilter(
   164→          filter: ui.ImageFilter.blur(sigmaX: 12, sigmaY: 12),
   165→          child: surface,
   166→        ),
   167→      );
   168→    }
   169→
   170→    return surface;
   171→  }
   172→}
