   174→// ---------------------------------------------------------------------------
   175→// Border painter
   176→// ---------------------------------------------------------------------------
   177→
   178→/// Paints dashed, dotted, or gradient borders around a rounded rectangle.
   179→class _OiBorderPainter extends CustomPainter {
   180→  const _OiBorderPainter({required this.style, required this.radius});
   181→
   182→  final OiBorderStyle style;
   183→  final BorderRadius radius;
   184→
   185→  @override
   186→  void paint(Canvas canvas, Size size) {
   187→    final paint = Paint()
   188→      ..strokeWidth = style.width
   189→      ..style = PaintingStyle.stroke;
   190→
   191→    if (style.gradient != null) {
   192→      final rect = Offset.zero & size;
   193→      paint.shader = style.gradient!.createShader(rect);
   194→    } else {
   195→      paint.color = style.color;
   196→    }
   197→
   198→    final rrect = RRect.fromRectAndCorners(
   199→      Offset.zero & size,
   200→      topLeft: radius.topLeft,
   201→      topRight: radius.topRight,
   202→      bottomLeft: radius.bottomLeft,
   203→      bottomRight: radius.bottomRight,
   204→    );
   205→
   206→    if (style.lineStyle == OiBorderLineStyle.solid) {
   207→      canvas.drawRRect(rrect, paint);
   208→      return;
   209→    }
   210→
   211→    // Approximate perimeter for dash/dot spacing.
   212→    final perimeter = _rrectPerimeter(rrect);
   213→    final dashLength = style.lineStyle == OiBorderLineStyle.dashed
   214→        ? style.width * 4
   215→        : 0.0;
   216→    final dotLength = style.lineStyle == OiBorderLineStyle.dotted
   217→        ? style.width
   218→        : 0.0;
   219→    final segmentLength = style.lineStyle == OiBorderLineStyle.dashed
   220→        ? dashLength
   221→        : dotLength;
   222→    final gapLength = segmentLength * 1.5;
   223→
   224→    final path = Path()..addRRect(rrect);
   225→    final metrics = path.computeMetrics();
   226→
   227→    for (final metric in metrics) {
   228→      var distance = 0.0;
   229→      var draw = true;
   230→      while (distance < metric.length) {
   231→        final length = draw ? segmentLength : gapLength;
   232→        if (draw) {
   233→          canvas.drawPath(
   234→            metric.extractPath(
   235→              distance,
   236→              distance + math.min(length, perimeter),
   237→            ),
   238→            paint,
   239→          );
   240→        }
   241→        distance += length;
   242→        draw = !draw;
   243→      }
   244→    }
   245→  }
   246→
   247→  double _rrectPerimeter(RRect rrect) {
   248→    // Approximate: sum of straight edges + arc lengths at corners.
   249→    final w = rrect.width;
   250→    final h = rrect.height;
   251→    final tl = rrect.tlRadiusX + rrect.tlRadiusY;
   252→    final tr = rrect.trRadiusX + rrect.trRadiusY;
   253→    final bl = rrect.blRadiusX + rrect.blRadiusY;
   254→    final br = rrect.brRadiusX + rrect.brRadiusY;
   255→    return 2 * w + 2 * h + (tl + tr + bl + br) * (math.pi / 4 - 1);
   256→  }
   257→
   258→  @override
   259→  bool shouldRepaint(_OiBorderPainter oldDelegate) =>
   260→      oldDelegate.style != style || oldDelegate.radius != radius;
   261→}
