    13→/// or [OiDivider.withContent] to show an arbitrary widget.
    14→///
    15→/// {@category Primitives}
    16→class OiDivider extends StatelessWidget {
    17→  /// Creates a plain [OiDivider].
    18→  const OiDivider({
    19→    this.axis = Axis.horizontal,
    20→    this.thickness = 1.0,
    21→    this.color,
    22→    this.style = OiBorderLineStyle.solid,
    23→    this.spacing = 0,
    24→    super.key,
    25→  }) : _label = null,
    26→       _content = null;
    27→
    28→  /// Creates a [OiDivider] with a text [label] centred in the line.
    29→  const OiDivider.withLabel(
    30→    String label, {
    31→    this.axis = Axis.horizontal,
    32→    this.thickness = 1.0,
    33→    this.color,
    34→    this.style = OiBorderLineStyle.solid,
    35→    this.spacing = 0,
    36→    super.key,
    37→  }) : _label = label,
    38→       _content = null;
