    45→    this.thickness = 1.0,
    46→    this.color,
    47→    this.style = OiBorderLineStyle.solid,
    48→    this.spacing = 0,
    49→    super.key,
    50→  }) : _label = null,
    51→       _content = content;
    52→
    53→  /// The direction of the divider line.
    54→  final Axis axis;
    55→
    56→  /// Stroke thickness in logical pixels.
    57→  final double thickness;
    58→
    59→  /// Color of the divider.  Defaults to [OiColorScheme.border] when null.
    60→  final Color? color;
    61→
    62→  /// The line drawing style: solid, dashed, or dotted.
    63→  final OiBorderLineStyle style;
    64→
    65→  /// Extra space added on both sides of the divider.
    66→  ///
    67→  /// For a horizontal divider this is vertical padding; for a vertical
    68→  /// divider it is horizontal padding.
    69→  final double spacing;
    70→
    71→  final String? _label;
    72→  final Widget? _content;
    73→
    74→  // ---------------------------------------------------------------------------
    75→
    76→  Color _resolvedColor(BuildContext context) => color ?? context.colors.border;
    77→
    78→  Widget _buildLine(BuildContext context, {bool flex = true}) {
    79→    final resolvedColor = _resolvedColor(context);
    80→
    81→    if (style == OiBorderLineStyle.solid) {
    82→      final line = axis == Axis.horizontal
    83→          ? Container(height: thickness, color: resolvedColor)
    84→          : Container(width: thickness, color: resolvedColor);
    85→      return flex ? Expanded(child: line) : line;
    86→    }
    87→
    88→    // Dashed / dotted — delegate to CustomPainter.
    89→    final painter = _OiDividerPainter(
    90→      axis: axis,
    91→      thickness: thickness,
    92→      color: resolvedColor,
    93→      style: style,
    94→    );
    95→    final line = axis == Axis.horizontal
    96→        ? SizedBox(
    97→            height: thickness,
    98→            child: CustomPaint(painter: painter),
    99→          )
   100→        : SizedBox(
   101→            width: thickness,
   102→            child: CustomPaint(painter: painter),
   103→          );
   104→    return flex ? Expanded(child: line) : line;
   105→  }
   106→
   107→  @override
   108→  Widget build(BuildContext context) {
   109→    final hasContent = _label != null || _content != null;
   110→    final centreWidget = _label != null ? Text(_label) : _content;
   111→
   112→    Widget divider;
   113→
   114→    if (!hasContent) {
   115→      divider = _buildLine(context, flex: false);
   116→    } else if (axis == Axis.horizontal) {
   117→      divider = Row(
   118→        children: [
   119→          _buildLine(context),
   120→          Padding(
   121→            padding: const EdgeInsets.symmetric(horizontal: 8),
   122→            child: centreWidget,
   123→          ),
   124→          _buildLine(context),
   125→        ],
   126→      );
   127→    } else {
   128→      divider = Column(
   129→        children: [
   130→          _buildLine(context),
   131→          Padding(
   132→            padding: const EdgeInsets.symmetric(vertical: 8),
   133→            child: centreWidget,
   134→          ),
   135→          _buildLine(context),
   136→        ],
   137→      );
   138→    }
   139→
   140→    if (spacing > 0) {
   141→      divider = axis == Axis.horizontal
   142→          ? Padding(
   143→              padding: EdgeInsets.symmetric(vertical: spacing),
   144→              child: divider,
   145→            )
   146→          : Padding(
   147→              padding: EdgeInsets.symmetric(horizontal: spacing),
   148→              child: divider,
   149→            );
   150→    }
   151→
   152→    return divider;
   153→  }
   154→}
   155→
   156→// ---------------------------------------------------------------------------
   157→// Painter
   158→// ---------------------------------------------------------------------------
   159→
   160→/// Paints a dashed or dotted line along the given [axis].
   161→class _OiDividerPainter extends CustomPainter {
   162→  const _OiDividerPainter({
   163→    required this.axis,
   164→    required this.thickness,
   165→    required this.color,
   166→    required this.style,
   167→  });
   168→
   169→  final Axis axis;
   170→  final double thickness;
   171→  final Color color;
   172→  final OiBorderLineStyle style;
   173→
   174→  @override
   175→  void paint(Canvas canvas, Size size) {
   176→    final paint = Paint()
   177→      ..color = color
   178→      ..strokeWidth = thickness
   179→      ..style = PaintingStyle.stroke;
   180→
   181→    final segmentLength = style == OiBorderLineStyle.dashed
   182→        ? thickness * 4
   183→        : thickness;
   184→    final gapLength = segmentLength * 1.5;
   185→    final total = axis == Axis.horizontal ? size.width : size.height;
   186→
   187→    var pos = 0.0;
   188→    var draw = true;
   189→
   190→    while (pos < total) {
   191→      final len = draw ? segmentLength : gapLength;
   192→      final end = math.min(pos + len, total);
   193→      if (draw) {
   194→        final p1 = axis == Axis.horizontal
   195→            ? Offset(pos, size.height / 2)
   196→            : Offset(size.width / 2, pos);
   197→        final p2 = axis == Axis.horizontal
   198→            ? Offset(end, size.height / 2)
   199→            : Offset(size.width / 2, end);
   200→        canvas.drawLine(p1, p2, paint);
   201→      }
   202→      pos += len;
   203→      draw = !draw;
   204→    }
   205→  }
   206→
   207→  @override
   208→  bool shouldRepaint(_OiDividerPainter oldDelegate) =>
   209→      oldDelegate.axis != axis ||
   210→      oldDelegate.thickness != thickness ||
   211→      oldDelegate.color != color ||
   212→      oldDelegate.style != style;
   213→}
