    89→
    90→class _OiTappableState extends State<OiTappable> {
    91→  bool _isHovered = false;
    92→  bool _isPressed = false;
    93→  bool _isFocused = false;
    94→
    95→  // ── State helpers ──────────────────────────────────────────────────────────
    96→
    97→  void _setHovered(bool value) {
    98→    if (_isHovered != value) setState(() => _isHovered = value);
    99→  }
   100→
   101→  void _setPressed(bool value) {
   102→    if (_isPressed != value) setState(() => _isPressed = value);
   103→  }
   104→
   105→  void _setFocused(bool value) {
   106→    if (_isFocused != value) setState(() => _isFocused = value);
   107→  }
   108→
   109→  // ── Effective style ────────────────────────────────────────────────────────
   110→
   111→  OiInteractiveStyle _effectiveStyle(OiEffectsTheme effects) {
   112→    if (!widget.enabled) return OiInteractiveStyle.none;
   113→    if (_isPressed) return effects.active;
   114→    if (_isHovered) return effects.hover;
   115→    if (_isFocused) return effects.focus;
   116→    return OiInteractiveStyle.none;
   117→  }
   118→
   119→  // ── Gesture callbacks ──────────────────────────────────────────────────────
   120→
   121→  void _handleTapDown(TapDownDetails _) => _setPressed(true);
   122→  void _handleTapUp(TapUpDetails _) => _setPressed(false);
   123→  void _handleTapCancel() => _setPressed(false);
   124→
   125→  void _handleTap() {
   126→    if (widget.enabled) widget.onTap?.call();
   127→  }
   128→
   129→  void _handleDoubleTap() {
   130→    if (widget.enabled) widget.onDoubleTap?.call();
   131→  }
   132→
   133→  void _handleLongPress() {
   134→    if (widget.enabled) widget.onLongPress?.call();
   135→  }
