   137→  // ── Build ──────────────────────────────────────────────────────────────────
   138→
   139→  @override
   140→  Widget build(BuildContext context) {
   141→    final effects = context.effects;
   142→    final animations = context.animations;
   143→    final density = OiDensityScope.of(context);
   144→    final isTouch = density == OiDensity.comfortable;
   145→    final style = _effectiveStyle(effects);
   146→
   147→    final effectiveCursor =
   148→        widget.cursor ??
   149→        (widget.enabled ? SystemMouseCursors.click : SystemMouseCursors.basic);
   150→
   151→    // ── Build inner content with state overlay ───────────────────────────────
   152→    // ignore: omit_local_variable_types
   153→    Widget content = widget.child;
   154→
   155→    // Background overlay for the current state.
   156→    if (style.backgroundOverlay.a > 0) {
   157→      content = Stack(
   158→        fit: StackFit.passthrough,
   159→        children: [
   160→          content,
   161→          Positioned.fill(
   162→            child: IgnorePointer(
   163→              child: ColoredBox(color: style.backgroundOverlay),
   164→            ),
   165→          ),
   166→        ],
   167→      );
   168→    }
   169→
   170→    // Halo / glow rendered as a DecoratedBox behind the content.
   171→    final halo = style.halo; // ignore: omit_local_variable_types
   172→    if (halo != OiHaloStyle.none &&
   173→        (halo.color.a > 0 || halo.spread > 0 || halo.blur > 0)) {
   174→      content = DecoratedBox(
   175→        decoration: BoxDecoration(boxShadow: [halo.toBoxShadow()]),
   176→        child: content,
   177→      );
   178→    }
   179→
   180→    // Scale transform for pressed states.
   181→    if (style.scale != 1) {
   182→      content = Transform.scale(scale: style.scale, child: content);
   183→    }
   184→
   185→    // Reduced opacity when disabled.
   186→    if (!widget.enabled) {
   187→      content = Opacity(opacity: 0.4, child: content);
   188→    }
   189→
   190→    // Enforce minimum 48 dp touch target on touch devices.
