   195→    // Gesture detection.
   196→    content = GestureDetector(
   197→      onTap: _handleTap,
   198→      onDoubleTap: widget.onDoubleTap != null ? _handleDoubleTap : null,
   199→      onLongPress: widget.onLongPress != null ? _handleLongPress : null,
   200→      onTapDown: _handleTapDown,
   201→      onTapUp: _handleTapUp,
   202→      onTapCancel: _handleTapCancel,
   203→      behavior: HitTestBehavior.opaque,
   204→      child: content,
   205→    );
   206→
   207→    // Hover region — only active on pointer devices.
   208→    if (!isTouch) {
   209→      content = MouseRegion(
   210→        cursor: effectiveCursor,
   211→        onEnter: (_) {
   212→          if (widget.enabled) {
   213→            _setHovered(true);
   214→            widget.onHover?.call(true);
