   281→      math.max(childSize.width, _kMinTouchTarget),
   282→      math.max(childSize.height, _kMinTouchTarget),
   283→    );
   284→  }
   285→
   286→  @override
   287→  void performLayout() {
   288→    super.performLayout();
   289→    size = Size(
   290→      math.max(size.width, _kMinTouchTarget),
   291→      math.max(size.height, _kMinTouchTarget),
   292→    );
   293→  }
   294→}
