   148→    _bottomSheetEntry = null;
   149→  }
   150→
   151→  /// Returns the [targetAnchor], [followerAnchor], and [linkedOffset] for the
   152→  /// given [alignment] and [gap].
   153→  ({Alignment targetAnchor, Alignment followerAnchor, Offset linkedOffset})
   154→  _anchorsFor(OiFloatingAlignment alignment, double gap) {
   155→    switch (alignment) {
   156→      case OiFloatingAlignment.topStart:
   157→        return (
   158→          targetAnchor: Alignment.topLeft,
   159→          followerAnchor: Alignment.bottomLeft,
   160→          linkedOffset: Offset(0, -gap),
   161→        );
   162→      case OiFloatingAlignment.topCenter:
   163→        return (
   164→          targetAnchor: Alignment.topCenter,
   165→          followerAnchor: Alignment.bottomCenter,
   166→          linkedOffset: Offset(0, -gap),
   167→        );
   168→      case OiFloatingAlignment.topEnd:
   169→        return (
   170→          targetAnchor: Alignment.topRight,
   171→          followerAnchor: Alignment.bottomRight,
   172→          linkedOffset: Offset(0, -gap),
   173→        );
   174→      case OiFloatingAlignment.bottomStart:
   175→        return (
   176→          targetAnchor: Alignment.bottomLeft,
   177→          followerAnchor: Alignment.topLeft,
   178→          linkedOffset: Offset(0, gap),
   179→        );
   180→      case OiFloatingAlignment.bottomCenter:
   181→        return (
   182→          targetAnchor: Alignment.bottomCenter,
   183→          followerAnchor: Alignment.topCenter,
   184→          linkedOffset: Offset(0, gap),
   185→        );
   186→      case OiFloatingAlignment.bottomEnd:
   187→        return (
   188→          targetAnchor: Alignment.bottomRight,
   189→          followerAnchor: Alignment.topRight,
   190→          linkedOffset: Offset(0, gap),
   191→        );
   192→      case OiFloatingAlignment.leftStart:
   193→        return (
   194→          targetAnchor: Alignment.topLeft,
   195→          followerAnchor: Alignment.topRight,
   196→          linkedOffset: Offset(-gap, 0),
   197→        );
   198→      case OiFloatingAlignment.leftCenter:
   199→        return (
   200→          targetAnchor: Alignment.centerLeft,
   201→          followerAnchor: Alignment.centerRight,
   202→          linkedOffset: Offset(-gap, 0),
   203→        );
   204→      case OiFloatingAlignment.leftEnd:
   205→        return (
   206→          targetAnchor: Alignment.bottomLeft,
   207→          followerAnchor: Alignment.bottomRight,
   208→          linkedOffset: Offset(-gap, 0),
   209→        );
   210→      case OiFloatingAlignment.rightStart:
   211→        return (
   212→          targetAnchor: Alignment.topRight,
   213→          followerAnchor: Alignment.topLeft,
   214→          linkedOffset: Offset(gap, 0),
   215→        );
   216→      case OiFloatingAlignment.rightCenter:
   217→        return (
   218→          targetAnchor: Alignment.centerRight,
   219→          followerAnchor: Alignment.centerLeft,
   220→          linkedOffset: Offset(gap, 0),
   221→        );
   222→      case OiFloatingAlignment.rightEnd:
   223→        return (
   224→          targetAnchor: Alignment.bottomRight,
   225→          followerAnchor: Alignment.bottomLeft,
   226→          linkedOffset: Offset(gap, 0),
   227→        );
   228→    }
   229→  }
   230→
   231→  /// Returns the opposite alignment used for auto-flip.
   232→  OiFloatingAlignment _flippedAlignment(OiFloatingAlignment alignment) {
   233→    switch (alignment) {
   234→      case OiFloatingAlignment.topStart:
   235→        return OiFloatingAlignment.bottomStart;
   236→      case OiFloatingAlignment.topCenter:
   237→        return OiFloatingAlignment.bottomCenter;
   238→      case OiFloatingAlignment.topEnd:
   239→        return OiFloatingAlignment.bottomEnd;
   240→      case OiFloatingAlignment.bottomStart:
   241→        return OiFloatingAlignment.topStart;
   242→      case OiFloatingAlignment.bottomCenter:
   243→        return OiFloatingAlignment.topCenter;
   244→      case OiFloatingAlignment.bottomEnd:
   245→        return OiFloatingAlignment.topEnd;
   246→      case OiFloatingAlignment.leftStart:
   247→        return OiFloatingAlignment.rightStart;
   248→      case OiFloatingAlignment.leftCenter:
   249→        return OiFloatingAlignment.rightCenter;
   250→      case OiFloatingAlignment.leftEnd:
   251→        return OiFloatingAlignment.rightEnd;
   252→      case OiFloatingAlignment.rightStart:
   253→        return OiFloatingAlignment.leftStart;
   254→      case OiFloatingAlignment.rightCenter:
   255→        return OiFloatingAlignment.leftCenter;
   256→      case OiFloatingAlignment.rightEnd:
   257→        return OiFloatingAlignment.leftEnd;
   258→    }
   259→  }
   260→
   261→  OiFloatingAlignment _resolvedAlignment() {
   262→    if (!widget.autoFlip) return widget.alignment;
   263→
   264→    final renderBox = context.findRenderObject() as RenderBox?;
   265→    if (renderBox == null || !renderBox.hasSize) return widget.alignment;
   266→
   267→    final viewportSize = MediaQuery.sizeOf(context);
   268→    final globalPosition = renderBox.localToGlobal(Offset.zero);
   269→
   270→    switch (widget.alignment) {
   271→      case OiFloatingAlignment.topStart:
   272→      case OiFloatingAlignment.topCenter:
   273→      case OiFloatingAlignment.topEnd:
   274→        // Flip to bottom if not enough space above.
   275→        if (globalPosition.dy < 100) {
   276→          return _flippedAlignment(widget.alignment);
   277→        }
   278→      case OiFloatingAlignment.bottomStart:
   279→      case OiFloatingAlignment.bottomCenter:
   280→      case OiFloatingAlignment.bottomEnd:
   281→        // Flip to top if not enough space below.
   282→        if (globalPosition.dy + renderBox.size.height + 100 >
   283→            viewportSize.height) {
   284→          return _flippedAlignment(widget.alignment);
   285→        }
   286→      case OiFloatingAlignment.leftStart:
   287→      case OiFloatingAlignment.leftCenter:
   288→      case OiFloatingAlignment.leftEnd:
   289→        // Flip to right if not enough space to the left.
   290→        if (globalPosition.dx < 100) {
   291→          return _flippedAlignment(widget.alignment);
   292→        }
   293→      case OiFloatingAlignment.rightStart:
   294→      case OiFloatingAlignment.rightCenter:
   295→      case OiFloatingAlignment.rightEnd:
   296→        // Flip to left if not enough space to the right.
   297→        if (globalPosition.dx + renderBox.size.width + 100 >
   298→            viewportSize.width) {
   299→          return _flippedAlignment(widget.alignment);
   300→        }
   301→    }
   302→    return widget.alignment;
   303→  }
   304→
   305→  @override
   306→  Widget build(BuildContext context) {
   307→    final isCompact = context.isCompact;
   308→    final useBottomSheet = widget.bottomSheetOnCompact && isCompact;
   309→
   310→    final resolvedAlignment = _resolvedAlignment();
   311→    final anchors = _anchorsFor(resolvedAlignment, widget.gap);
   312→    final extraOffset = widget.offset ?? Offset.zero;
   313→    final linkedOffset = anchors.linkedOffset + extraOffset;
   314→
   315→    final anchorWidget = CompositedTransformTarget(
   316→      link: _layerLink,
   317→      child: widget.anchor,
   318→    );
   319→
   320→    if (useBottomSheet) {
   321→      // On compact: the bottom sheet is managed via OverlayEntry;
   322→      // just render the anchor here.
   323→      return anchorWidget;
   324→    }
   325→
   326→    final follower = CompositedTransformFollower(
   327→      link: _layerLink,
   328→      showWhenUnlinked: false,
   329→      targetAnchor: anchors.targetAnchor,
   330→      followerAnchor: anchors.followerAnchor,
   331→      offset: linkedOffset,
   332→      child: Visibility(
   333→        visible: widget.visible,
   334→        maintainState: true,
   335→        maintainAnimation: true,
   336→        child: widget.child,
   337→      ),
   338→    );
   339→
   340→    return Stack(
   341→      clipBehavior: Clip.none,
   342→      children: [
   343→        anchorWidget,
   344→        Positioned(width: 0, height: 0, child: follower),
   345→      ],
   346→    );
   347→  }
   348→}
