     4→/// Renders its [child] inside the nearest [Overlay] when [active] is true.
     5→///
     6→/// This is useful for "portalling" content out of its DOM-like position in the
     7→/// widget tree so that it appears above all other content (e.g. tooltips,
     8→/// dropdowns, menus). When [active] is false, nothing is rendered in the
     9→/// overlay.
    10→///
    11→/// The portal requires an [Overlay] ancestor in the widget tree (provided
    12→/// automatically by [OiApp] via [Navigator] / [WidgetsApp]).
    13→///
    14→/// ```dart
    15→/// OiPortal(
    16→///   active: _showMenu,
    17→///   child: MenuPanel(...),
    18→/// )
    19→/// ```
    20→///
    21→/// {@category Primitives}
    22→class OiPortal extends StatefulWidget {
    23→  /// Creates an [OiPortal].
    24→  const OiPortal({required this.child, this.active = false, super.key});
    25→
    26→  /// The widget to render in the overlay when [active] is true.
    27→  final Widget child;
    28→
    29→  /// Whether the portal is currently active (rendering in the overlay).
    30→  ///
    31→  /// When changed from false to true the [child] is inserted into the overlay.
    32→  /// When changed from true to false the overlay entry is removed.
    33→  final bool active;
    34→
    35→  @override
    36→  State<OiPortal> createState() => _OiPortalState();
    37→}
    38→
    39→class _OiPortalState extends State<OiPortal> {
    40→  OverlayEntry? _entry;
    41→
    42→  @override
    43→  void initState() {
    44→    super.initState();
    45→    if (widget.active) {
    46→      // Defer insert so it never runs while the framework is building.
    47→      _scheduleInsert();
    48→    }
    49→  }
    50→
    51→  @override
    52→  void didUpdateWidget(OiPortal oldWidget) {
    53→    super.didUpdateWidget(oldWidget);
    54→    if (widget.active != oldWidget.active) {
    55→      if (widget.active) {
    56→        _scheduleInsert();
    57→      } else {
    58→        // Defer removal to avoid modifying the overlay during a build.
    59→        _scheduleRemove();
    60→      }
    61→    } else if (widget.active && widget.child != oldWidget.child) {
    62→      // Defer markNeedsBuild to avoid calling it during a build phase.
    63→      _scheduleMarkNeedsBuild();
    64→    }
    65→  }
    66→
    67→  @override
    68→  void dispose() {
    69→    _doRemoveEntry();
    70→    super.dispose();
    71→  }
    72→
    73→  void _scheduleInsert() {
    74→    SchedulerBinding.instance.addPostFrameCallback((_) {
    75→      if (mounted && widget.active) {
    76→        _doInsertEntry();
    77→      }
    78→    });
    79→  }
    80→
    81→  void _scheduleRemove() {
    82→    SchedulerBinding.instance.addPostFrameCallback((_) {
    83→      if (mounted && !widget.active) {
    84→        _doRemoveEntry();
    85→      }
    86→    });
    87→  }
    88→
    89→  void _scheduleMarkNeedsBuild() {
    90→    SchedulerBinding.instance.addPostFrameCallback((_) {
    91→      if (mounted) {
    92→        _entry?.markNeedsBuild();
    93→      }
    94→    });
    95→  }
    96→
    97→  void _doInsertEntry() {
    98→    if (_entry != null) {
    99→      _entry!.markNeedsBuild();
   100→      return;
   101→    }
   102→    final overlay = Overlay.maybeOf(context);
   103→    if (overlay == null) return;
   104→    _entry = OverlayEntry(builder: (_) => widget.child);
   105→    overlay.insert(_entry!);
   106→  }
   107→
   108→  void _doRemoveEntry() {
   109→    _entry?.remove();
   110→    _entry?.dispose();
   111→    _entry = null;
   112→  }
   113→
   114→  @override
   115→  Widget build(BuildContext context) {
   116→    // The portal itself is invisible in-tree; content lives in the overlay.
   117→    return const SizedBox.shrink();
   118→  }
   119→}
