     6→/// Transition animations for showing/hiding widgets.
     7→///
     8→/// {@category Primitives}
     9→enum OiTransition {
    10→  /// No animation — the widget appears or disappears instantly.
    11→  none,
    12→
    13→  /// Fade in/out.
    14→  fade,
    15→
    16→  /// Fade combined with a scale from 0.9 to 1.0.
    17→  fadeScale,
    18→
    19→  /// Slide upward while fading in (slides down while fading out).
    20→  slideUp,
    21→
    22→  /// Slide downward while fading in (slides up while fading out).
    23→  slideDown,
    24→
    25→  /// Slide in from the left while fading in.
    26→  slideLeft,
    27→
    28→  /// Slide in from the right while fading in.
    29→  slideRight,
    30→}
    31→
    32→/// Animates showing and hiding a [child] widget with configurable transitions.
    33→///
    34→/// When [visible] becomes true the widget runs a forward animation. When
    35→/// [visible] becomes false the widget runs a reverse animation. Use
    36→/// [transition] to control the animation style. Use [maintainState] to keep
    37→/// the child widget in the tree even when hidden (default true).
    38→///
    39→/// Use the [OiVisibility.responsive] constructor to apply different transitions
    40→/// at compact vs. expanded breakpoints.
    41→///
    42→/// ```dart
    43→/// OiVisibility(
    44→///   visible: _isOpen,
    45→///   transition: OiTransition.fadeScale,
    46→///   child: MyPanel(),
    47→/// )
    48→/// ```
    49→///
    50→/// {@category Primitives}
    51→class OiVisibility extends StatefulWidget {
    52→  /// Creates an [OiVisibility] with a single transition style.
    53→  const OiVisibility({
    54→    required this.visible,
    55→    required this.child,
    56→    this.transition = OiTransition.fade,
    57→    this.maintainState = true,
    58→    super.key,
    59→  }) : _compactTransition = null,
    60→       _expandedTransition = null;
    61→
    62→  /// Creates an [OiVisibility] with responsive transitions.
    63→  ///
    64→  /// Uses [compactTransition] on compact breakpoints (width < 600dp) and
    65→  /// [expandedTransition] on all wider breakpoints.
    66→  const OiVisibility.responsive({
    67→    required this.visible,
    68→    required this.child,
    69→    OiTransition compactTransition = OiTransition.slideUp,
    70→    OiTransition expandedTransition = OiTransition.fade,
    71→    this.maintainState = true,
    72→    super.key,
    73→  }) : transition = expandedTransition,
    74→       _compactTransition = compactTransition,
    75→       _expandedTransition = expandedTransition;
    76→
    77→  /// Whether the child is visible.
    78→  final bool visible;
    79→
    80→  /// The child to show or hide.
    81→  final Widget child;
    82→
    83→  /// The transition animation to use.
    84→  ///
    85→  /// Ignored when this widget was created with [OiVisibility.responsive].
    86→  final OiTransition transition;
    87→
    88→  /// Whether to keep the child in the widget tree when hidden.
    89→  ///
    90→  /// When false, the child is removed from the tree after the hide animation
    91→  /// completes. Defaults to true.
    92→  final bool maintainState;
    93→
    94→  // Internal fields for the responsive constructor.
    95→  final OiTransition? _compactTransition;
    96→  final OiTransition? _expandedTransition;
    97→
    98→  @override
    99→  State<OiVisibility> createState() => _OiVisibilityState();
   100→}
   101→
   102→class _OiVisibilityState extends State<OiVisibility>
   103→    with SingleTickerProviderStateMixin {
   104→  late AnimationController _controller;
   105→  late Animation<double> _animation;
   106→
   107→  /// Whether the child is currently in the tree (relevant when
   108→  /// maintainState=false).
   109→  bool _inTree = false;
   110→
   111→  @override
   112→  void initState() {
   113→    super.initState();
   114→    _inTree = widget.visible;
   115→    _controller = AnimationController(
   116→      vsync: this,
   117→      value: widget.visible ? 1.0 : 0.0,
   118→    );
   119→    _animation = CurvedAnimation(
   120→      parent: _controller,
   121→      curve: Curves.easeOut,
   122→      reverseCurve: Curves.easeIn,
   123→    );
   124→  }
   125→
   126→  @override
   127→  void didChangeDependencies() {
   128→    super.didChangeDependencies();
   129→    _updateDuration();
   130→  }
   131→
   132→  @override
   133→  void didUpdateWidget(OiVisibility oldWidget) {
   134→    super.didUpdateWidget(oldWidget);
   135→    _updateDuration();
   136→    if (widget.visible != oldWidget.visible) {
   137→      if (widget.visible) {
   138→        setState(() => _inTree = true);
   139→        _controller.forward();
   140→      } else {
   141→        _controller.reverse().whenComplete(() {
   142→          if (mounted && !widget.visible && !widget.maintainState) {
   143→            setState(() => _inTree = false);
   144→          }
   145→        });
   146→      }
   147→    }
   148→  }
   149→
   150→  void _updateDuration() {
   151→    final reducedMotion = OiA11y.reducedMotion(context);
   152→    if (reducedMotion) {
   153→      _controller.duration = Duration.zero;
   154→      _controller.reverseDuration = Duration.zero;
   155→    } else {
   156→      final dur = context.animations.normal;
   157→      _controller.duration = dur;
   158→      _controller.reverseDuration = dur;
   159→    }
   160→  }
   161→
   162→  @override
   163→  void dispose() {
   164→    _controller.dispose();
   165→    super.dispose();
   166→  }
   167→
   168→  OiTransition _resolvedTransition() {
   169→    if (widget._compactTransition != null &&
   170→        widget._expandedTransition != null) {
   171→      return context.isCompact
   172→          ? widget._compactTransition!
   173→          : widget._expandedTransition!;
   174→    }
   175→    return widget.transition;
   176→  }
   177→
   178→  Widget _buildTransitionedChild(OiTransition transition, Widget child) {
   179→    switch (transition) {
   180→      case OiTransition.none:
   181→        return child;
   182→
   183→      case OiTransition.fade:
   184→        return FadeTransition(opacity: _animation, child: child);
   185→
   186→      case OiTransition.fadeScale:
   187→        final scaleTween = Tween<double>(begin: 0.9, end: 1);
   188→        return FadeTransition(
   189→          opacity: _animation,
   190→          child: ScaleTransition(
   191→            scale: scaleTween.animate(_animation),
   192→            child: child,
   193→          ),
   194→        );
   195→
   196→      case OiTransition.slideUp:
   197→        final slideTween = Tween<Offset>(
   198→          begin: const Offset(0, 0.1),
   199→          end: Offset.zero,
   200→        );
   201→        return FadeTransition(
   202→          opacity: _animation,
   203→          child: SlideTransition(
   204→            position: slideTween.animate(_animation),
   205→            child: child,
   206→          ),
   207→        );
   208→
   209→      case OiTransition.slideDown:
   210→        final slideTween = Tween<Offset>(
   211→          begin: const Offset(0, -0.1),
   212→          end: Offset.zero,
   213→        );
   214→        return FadeTransition(
   215→          opacity: _animation,
   216→          child: SlideTransition(
   217→            position: slideTween.animate(_animation),
   218→            child: child,
   219→          ),
   220→        );
   221→
   222→      case OiTransition.slideLeft:
   223→        final slideTween = Tween<Offset>(
   224→          begin: const Offset(0.1, 0),
   225→          end: Offset.zero,
   226→        );
   227→        return FadeTransition(
   228→          opacity: _animation,
   229→          child: SlideTransition(
   230→            position: slideTween.animate(_animation),
   231→            child: child,
   232→          ),
   233→        );
   234→
   235→      case OiTransition.slideRight:
   236→        final slideTween = Tween<Offset>(
   237→          begin: const Offset(-0.1, 0),
   238→          end: Offset.zero,
   239→        );
   240→        return FadeTransition(
   241→          opacity: _animation,
   242→          child: SlideTransition(
   243→            position: slideTween.animate(_animation),
   244→            child: child,
   245→          ),
   246→        );
   247→    }
   248→  }
   249→
   250→  @override
   251→  Widget build(BuildContext context) {
   252→    final transition = _resolvedTransition();
   253→
   254→    // For OiTransition.none use a plain Visibility widget.
   255→    if (transition == OiTransition.none) {
   256→      if (!widget.maintainState) {
   257→        return widget.visible ? widget.child : const SizedBox.shrink();
   258→      }
   259→      return Visibility(visible: widget.visible, child: widget.child);
   260→    }
   261→
   262→    // When maintainState=false and the child is not in tree, render nothing.
   263→    if (!widget.maintainState && !_inTree) {
   264→      return const SizedBox.shrink();
   265→    }
   266→
   267→    return _buildTransitionedChild(transition, widget.child);
   268→  }
   269→}
