    27→  /// Fixed number of columns. Mutually exclusive with [minColumnWidth].
    28→  final int? columns;
    29→
    30→  /// Minimum column width in logical pixels used to auto-compute the column
    31→  /// count. Mutually exclusive with [columns].
    32→  final double? minColumnWidth;
