    43→
    44→  @override
    45→  Widget build(BuildContext context) {
    46→    return LayoutBuilder(
    47→      builder: (context, constraints) {
    48→        final availableWidth = constraints.maxWidth;
    49→        final effectiveRowGap = rowGap ?? gap;
    50→
    51→        // Compute column count.
    52→        int cols;
    53→        if (columns != null) {
    54→          cols = columns!;
    55→        } else if (minColumnWidth != null && minColumnWidth! > 0) {
    56→          cols = math.max(1, (availableWidth / minColumnWidth!).floor());
    57→        } else {
    58→          cols = 1;
    59→        }
    60→
    61→        // Item width = (total width − gap * (cols − 1)) / cols
    62→        final itemWidth = cols <= 1
    63→            ? availableWidth
    64→            : (availableWidth - gap * (cols - 1)) / cols;
    65→
    66→        return Wrap(
    67→          spacing: gap,
    68→          runSpacing: effectiveRowGap,
    69→          children: children
    70→              .map((child) => SizedBox(width: itemWidth, child: child))
    71→              .toList(),
    72→        );
    73→      },
    74→    );
    75→  }
    76→}
