     3→// ── Node definition ───────────────────────────────────────────────────────────
     4→
     5→/// A single node in an [OiTree].
     6→///
     7→/// Nodes are immutable value objects. Build the tree by nesting [OiTreeNode]
     8→/// instances through the [children] list.
     9→///
    10→/// {@category Composites}
    11→@immutable
    12→class OiTreeNode<T> {
    13→  /// Creates an [OiTreeNode].
    14→  const OiTreeNode({
    15→    required this.id,
    16→    required this.label,
    17→    this.data,
    18→    this.children = const [],
    19→    this.leaf = false,
    20→    this.icon,
    21→  });
    22→
    23→  /// A unique identifier for this node within the tree.
    24→  final String id;
    25→
    26→  /// The human-readable label displayed for this node.
    27→  final String label;
    28→
    29→  /// Optional typed data payload attached to this node.
    30→  final T? data;
    31→
    32→  /// Direct children of this node.
    33→  final List<OiTreeNode<T>> children;
    34→
    35→  /// When `true`, this node is always treated as a leaf even if [children] is
    36→  /// non-empty (e.g. for lazy-loading scenarios).
    37→  final bool leaf;
    38→
    39→  /// Optional leading icon widget.
    40→  final Widget? icon;
    41→
    42→  /// Whether this node has any children and is not forced to leaf mode.
    43→  bool get hasChildren => !leaf && children.isNotEmpty;
    44→}
    45→
    46→// ── Controller ────────────────────────────────────────────────────────────────
    47→
    48→/// Controls the interactive state of an [OiTree].
    49→///
    50→/// Manages the set of expanded and selected node IDs. Notifies listeners on
    51→/// every state mutation so that an [OiTree] can rebuild.
    52→///
    53→/// {@category Composites}
    54→class OiTreeController extends ChangeNotifier {
    55→  /// Creates an [OiTreeController].
    56→  ///
    57→  /// [multiSelect] controls whether multiple nodes can be selected at once.
    58→  OiTreeController({this.multiSelect = false});
    59→
    60→  /// Whether multiple nodes may be selected simultaneously.
    61→  final bool multiSelect;
    62→
    63→  /// The set of IDs of currently expanded nodes.
    64→  final Set<String> expandedIds = {};
    65→
    66→  /// The set of IDs of currently selected nodes.
    67→  final Set<String> selectedIds = {};
    68→
    69→  // ── Expand / collapse ─────────────────────────────────────────────────────
    70→
    71→  /// Expands the node identified by [id].
    72→  ///
    73→  /// Does nothing (and does not notify) when [id] is already expanded.
    74→  void expand(String id) {
    75→    if (expandedIds.contains(id)) return;
    76→    expandedIds.add(id);
    77→    notifyListeners();
    78→  }
    79→
    80→  /// Collapses the node identified by [id].
    81→  ///
    82→  /// Does nothing (and does not notify) when [id] is already collapsed.
    83→  void collapse(String id) {
    84→    if (!expandedIds.remove(id)) return;
    85→    notifyListeners();
    86→  }
    87→
    88→  /// Toggles the expanded state of the node identified by [id].
    89→  void toggle(String id) {
    90→    if (expandedIds.contains(id)) {
    91→      expandedIds.remove(id);
    92→    } else {
    93→      expandedIds.add(id);
    94→    }
    95→    notifyListeners();
    96→  }
    97→
    98→  /// Expands all nodes in [ids].
    99→  void expandAll(Iterable<String> ids) {
   100→    final before = expandedIds.length;
   101→    expandedIds.addAll(ids);
   102→    if (expandedIds.length != before) notifyListeners();
   103→  }
   104→
   105→  /// Collapses all currently expanded nodes.
   106→  void collapseAll() {
   107→    if (expandedIds.isEmpty) return;
   108→    expandedIds.clear();
   109→    notifyListeners();
   110→  }
   111→
   112→  // ── Selection ─────────────────────────────────────────────────────────────
   113→
   114→  /// Selects the node identified by [id].
   115→  ///
   116→  /// When [multiSelect] is `false`, any previous selection is cleared first.
   117→  void select(String id) {
   118→    if (!multiSelect) selectedIds.clear();
   119→    if (selectedIds.contains(id)) return;
   120→    selectedIds.add(id);
   121→    notifyListeners();
   122→  }
   123→
   124→  /// Deselects the node identified by [id].
   125→  ///
   126→  /// Does nothing (and does not notify) when [id] is not selected.
   127→  void deselect(String id) {
   128→    if (!selectedIds.remove(id)) return;
   129→    notifyListeners();
   130→  }
   131→
   132→  /// Clears the entire selection.
   133→  ///
   134→  /// Does nothing (and does not notify) when already empty.
   135→  void clearSelection() {
   136→    if (selectedIds.isEmpty) return;
   137→    selectedIds.clear();
   138→    notifyListeners();
   139→  }
   140→
   141→  /// Whether the node identified by [id] is expanded.
   142→  bool expanded(String id) => expandedIds.contains(id);
   143→
   144→  /// Whether the node identified by [id] is selected.
   145→  bool selected(String id) => selectedIds.contains(id);
   146→}
   147→
   148→// ── Widget ────────────────────────────────────────────────────────────────────
   149→
   150→/// A hierarchical tree-view widget.
   151→///
   152→/// Renders a list of root [OiTreeNode]s, supporting expand/collapse,
   153→/// single or multi-node selection, lazy-loading children, and custom
   154→/// node builders.
   155→///
   156→/// ```dart
   157→/// OiTree<MyData>(
   158→///   nodes: [
   159→///     OiTreeNode(id: 'root', label: 'Root', children: [
   160→///       OiTreeNode(id: 'child1', label: 'Child 1'),
   161→///     ]),
   162→///   ],
   163→/// )
   164→/// ```
   165→///
   166→/// {@category Composites}
   167→class OiTree<T> extends StatefulWidget {
   168→  /// Creates an [OiTree].
   169→  const OiTree({
   170→    required this.nodes,
   171→    this.controller,
   172→    this.onNodeTap,
   173→    this.onNodeDoubleTap,
   174→    this.onExpansionChanged,
   175→    this.onSelectionChanged,
   176→    this.nodeBuilder,
   177→    this.indentWidth = 24,
   178→    this.rowHeight = 40,
   179→    this.selectable = false,
   180→    this.multiSelect = false,
   181→    this.showLines = false,
   182→    super.key,
   183→  });
   184→
   185→  /// The root nodes of the tree.
   186→  final List<OiTreeNode<T>> nodes;
   187→
   188→  /// Optional external controller. When `null`, the widget manages its own
   189→  /// internal [OiTreeController].
   190→  final OiTreeController? controller;
   191→
   192→  /// Called when the user taps a node.
   193→  final void Function(OiTreeNode<T> node)? onNodeTap;
   194→
   195→  /// Called when the user double-taps a node.
   196→  final void Function(OiTreeNode<T> node)? onNodeDoubleTap;
   197→
   198→  /// Called when a node's expansion state changes.
   199→  ///
   200→  /// The boolean argument is `true` when the node expands and `false`
   201→  /// when it collapses.
   202→  final void Function(OiTreeNode<T> node, {required bool expanded})?
   203→  onExpansionChanged;
   204→
   205→  /// Called when the selection changes.
   206→  final void Function(Set<String> selectedIds)? onSelectionChanged;
   207→
   208→  /// Custom builder for a single node row.
   209→  ///
   210→  /// When `null`, a default row is rendered with an optional leading icon,
   211→  /// an expand/collapse toggle for parent nodes, and the node's [label].
   212→  final Widget Function(
   213→    BuildContext context,
   214→    OiTreeNode<T> node,
   215→    int depth, {
   216→    required bool expanded,
   217→    required bool selected,
   218→  })?
   219→  nodeBuilder;
   220→
   221→  /// Indent width in logical pixels per depth level.
   222→  final double indentWidth;
   223→
   224→  /// Height of a single node row.
   225→  final double rowHeight;
   226→
   227→  /// Whether nodes can be selected by tapping.
   228→  final bool selectable;
   229→
   230→  /// Whether multiple nodes may be selected at once.
   231→  final bool multiSelect;
   232→
   233→  /// Whether to draw connecting lines between nodes.
   234→  final bool showLines;
   235→
   236→  @override
   237→  State<OiTree<T>> createState() => _OiTreeState<T>();
   238→}
   239→
   240→class _OiTreeState<T> extends State<OiTree<T>> {
   241→  late OiTreeController _ctrl;
   242→  bool _ownsController = false;
   243→
   244→  @override
   245→  void initState() {
   246→    super.initState();
   247→    _initController();
   248→  }
   249→
   250→  @override
   251→  void didUpdateWidget(OiTree<T> oldWidget) {
   252→    super.didUpdateWidget(oldWidget);
   253→    if (widget.controller != oldWidget.controller) {
   254→      _disposeControllerIfOwned();
   255→      _initController();
   256→    }
   257→  }
   258→
   259→  @override
   260→  void dispose() {
   261→    _disposeControllerIfOwned();
   262→    super.dispose();
   263→  }
   264→
   265→  void _initController() {
   266→    if (widget.controller != null) {
   267→      _ctrl = widget.controller!;
   268→      _ownsController = false;
   269→    } else {
   270→      _ctrl = OiTreeController(multiSelect: widget.multiSelect);
   271→      _ownsController = true;
   272→    }
   273→    _ctrl.addListener(_onControllerChanged);
   274→  }
   275→
   276→  void _disposeControllerIfOwned() {
   277→    _ctrl.removeListener(_onControllerChanged);
   278→    if (_ownsController) _ctrl.dispose();
   279→  }
   280→
   281→  void _onControllerChanged() => setState(() {});
   282→
   283→  // ── Flattened render list ─────────────────────────────────────────────────
   284→
   285→  /// Flattens the tree to a list of visible (depth, node) pairs.
   286→  List<({int depth, OiTreeNode<T> node})> get _visibleItems {
   287→    final items = <({int depth, OiTreeNode<T> node})>[];
   288→    void visit(OiTreeNode<T> node, int depth) {
   289→      items.add((depth: depth, node: node));
   290→      if (node.hasChildren && _ctrl.expanded(node.id)) {
   291→        for (final child in node.children) {
   292→          visit(child, depth + 1);
   293→        }
   294→      }
   295→    }
   296→
   297→    for (final root in widget.nodes) {
   298→      visit(root, 0);
   299→    }
   300→    return items;
   301→  }
   302→
   303→  // ── Event handlers ────────────────────────────────────────────────────────
   304→
   305→  void _handleTap(OiTreeNode<T> node) {
   306→    if (widget.selectable) {
   307→      if (_ctrl.multiSelect) {
   308→        if (_ctrl.selected(node.id)) {
   309→          _ctrl.deselect(node.id);
   310→        } else {
   311→          _ctrl.select(node.id);
   312→        }
   313→      } else {
   314→        _ctrl.select(node.id);
   315→      }
   316→      widget.onSelectionChanged?.call(Set.from(_ctrl.selectedIds));
   317→    }
   318→    widget.onNodeTap?.call(node);
   319→  }
   320→
   321→  void _handleDoubleTap(OiTreeNode<T> node) {
   322→    widget.onNodeDoubleTap?.call(node);
   323→  }
   324→
   325→  void _handleToggle(OiTreeNode<T> node) {
   326→    final willExpand = !_ctrl.expanded(node.id);
   327→    _ctrl.toggle(node.id);
   328→    widget.onExpansionChanged?.call(node, expanded: willExpand);
   329→  }
   330→
   331→  // ── Build ─────────────────────────────────────────────────────────────────
   332→
   333→  @override
   334→  Widget build(BuildContext context) {
   335→    final items = _visibleItems;
   336→    return ListView.builder(
   337→      itemCount: items.length,
   338→      itemExtent: widget.rowHeight,
   339→      itemBuilder: (ctx, i) {
   340→        final item = items[i];
   341→        return _buildNodeRow(ctx, item.node, item.depth);
   342→      },
   343→    );
   344→  }
   345→
   346→  Widget _buildNodeRow(BuildContext ctx, OiTreeNode<T> node, int depth) {
   347→    final expanded = _ctrl.expanded(node.id);
   348→    final selected = _ctrl.selected(node.id);
   349→
   350→    if (widget.nodeBuilder != null) {
   351→      return GestureDetector(
   352→        key: ValueKey('node_${node.id}'),
   353→        behavior: HitTestBehavior.opaque,
   354→        onTap: () => _handleTap(node),
   355→        onDoubleTap: () => _handleDoubleTap(node),
   356→        child: widget.nodeBuilder!(
   357→          ctx,
   358→          node,
   359→          depth,
   360→          expanded: expanded,
   361→          selected: selected,
   362→        ),
   363→      );
   364→    }
   365→
   366→    return _DefaultNodeRow<T>(
   367→      key: ValueKey('node_${node.id}'),
   368→      node: node,
   369→      depth: depth,
   370→      expanded: expanded,
   371→      selected: selected,
   372→      indentWidth: widget.indentWidth,
   373→      rowHeight: widget.rowHeight,
   374→      onTap: () => _handleTap(node),
   375→      onDoubleTap: () => _handleDoubleTap(node),
   376→      onToggle: node.hasChildren ? () => _handleToggle(node) : null,
   377→    );
   378→  }
   379→}
   380→
   381→// ── Default node row ──────────────────────────────────────────────────────────
   382→
   383→class _DefaultNodeRow<T> extends StatelessWidget {
   384→  const _DefaultNodeRow({
   385→    required this.node,
   386→    required this.depth,
   387→    required this.expanded,
   388→    required this.selected,
   389→    required this.indentWidth,
   390→    required this.rowHeight,
   391→    required this.onTap,
   392→    required this.onDoubleTap,
   393→    this.onToggle,
   394→    super.key,
   395→  });
   396→
   397→  final OiTreeNode<T> node;
   398→  final int depth;
   399→  final bool expanded;
   400→  final bool selected;
   401→  final double indentWidth;
   402→  final double rowHeight;
   403→  final VoidCallback onTap;
   404→  final VoidCallback onDoubleTap;
   405→  final VoidCallback? onToggle;
   406→
   407→  @override
   408→  Widget build(BuildContext context) {
   409→    Widget row = Row(
   410→      children: [
   411→        SizedBox(width: depth * indentWidth),
   412→        if (node.hasChildren)
   413→          GestureDetector(
   414→            key: ValueKey('toggle_${node.id}'),
   415→            behavior: HitTestBehavior.opaque,
   416→            onTap: onToggle,
   417→            child: SizedBox(
   418→              width: 24,
   419→              height: rowHeight,
   420→              child: Center(child: Text(expanded ? '▼' : '▶')),
   421→            ),
   422→          )
   423→        else
   424→          SizedBox(width: 24, height: rowHeight),
   425→        if (node.icon != null) ...[node.icon!, const SizedBox(width: 4)],
   426→        Expanded(
   427→          child: Align(
   428→            alignment: AlignmentDirectional.centerStart,
   429→            child: Text(
   430→              node.label,
   431→              key: ValueKey('label_${node.id}'),
   432→              overflow: TextOverflow.ellipsis,
   433→            ),
   434→          ),
   435→        ),
   436→      ],
   437→    );
   438→
   439→    if (selected) {
   440→      row = ColoredBox(color: const Color(0xFFDBEAFE), child: row);
   441→    }
   442→
   443→    return GestureDetector(
   444→      behavior: HitTestBehavior.opaque,
   445→      onTap: onTap,
   446→      onDoubleTap: onDoubleTap,
   447→      child: SizedBox(height: rowHeight, child: row),
   448→    );
   449→  }
   450→}
