   264→// ── Painters ──────────────────────────────────────────────────────────────
   265→
   266→class _AnnotationPainter extends CustomPainter {
   267→  _AnnotationPainter({required this.annotations, required this.defaultColor});
   268→
   269→  final List<OiAnnotation> annotations;
   270→  final Color defaultColor;
   271→
   272→  @override
   273→  void paint(Canvas canvas, Size size) {
   274→    for (final annotation in annotations) {
   275→      final color = annotation.color ?? defaultColor;
   276→      final paint = Paint()
   277→        ..color = color
   278→        ..strokeWidth = annotation.strokeWidth
   279→        ..style = PaintingStyle.stroke
   280→        ..strokeCap = StrokeCap.round;
   281→
   282→      switch (annotation.type) {
   283→        case OiAnnotationType.freehand:
   284→          if (annotation.points.length < 2) continue;
   285→          final path = Path()
   286→            ..moveTo(annotation.points.first.dx, annotation.points.first.dy);
   287→          for (var i = 1; i < annotation.points.length; i++) {
   288→            path.lineTo(annotation.points[i].dx, annotation.points[i].dy);
   289→          }
   290→          canvas.drawPath(path, paint);
   291→
   292→        case OiAnnotationType.rectangle:
   293→          if (annotation.points.length < 2) continue;
   294→          final rect = Rect.fromPoints(
   295→            annotation.points.first,
   296→            annotation.points.last,
   297→          );
   298→          canvas.drawRect(rect, paint);
   299→
   300→        case OiAnnotationType.circle:
   301→          if (annotation.points.length < 2) continue;
   302→          final rect = Rect.fromPoints(
   303→            annotation.points.first,
   304→            annotation.points.last,
   305→          );
   306→          canvas.drawOval(rect, paint);
   307→
   308→        case OiAnnotationType.arrow:
   309→          if (annotation.points.length < 2) continue;
   310→          final start = annotation.points.first;
   311→          final end = annotation.points.last;
   312→          canvas.drawLine(start, end, paint);
   313→          // Draw arrowhead
   314→          final direction = end - start;
   315→          final length = direction.distance;
   316→          if (length > 0) {
   317→            final unit = direction / length;
   318→            final headLength = annotation.strokeWidth * 4;
   319→            final p1 =
   320→                end -
   321→                Offset(
   322→                  unit.dx * headLength - unit.dy * headLength * 0.5,
   323→                  unit.dy * headLength + unit.dx * headLength * 0.5,
   324→                );
   325→            final p2 =
   326→                end -
   327→                Offset(
   328→                  unit.dx * headLength + unit.dy * headLength * 0.5,
   329→                  unit.dy * headLength - unit.dx * headLength * 0.5,
   330→                );
   331→            canvas.drawLine(end, p1, paint);
   332→            canvas.drawLine(end, p2, paint);
   333→          }
   334→
   335→        case OiAnnotationType.text:
   336→          if (annotation.points.isEmpty || annotation.text == null) continue;
   337→          (TextPainter(
   338→            text: TextSpan(
   339→              text: annotation.text,
   340→              style: TextStyle(
   341→                color: color,
   342→                fontSize: annotation.strokeWidth * 6,
   343→              ),
   344→            ),
   345→            textDirection: TextDirection.ltr,
   346→          )..layout()).paint(canvas, annotation.points.first);
   347→      }
   348→    }
   349→  }
   350→
   351→  @override
   352→  bool shouldRepaint(_AnnotationPainter oldDelegate) =>
   353→      annotations != oldDelegate.annotations;
   354→}
