   356→class _ActiveStrokePainter extends CustomPainter {
   357→  _ActiveStrokePainter({
   358→    required this.points,
   359→    required this.color,
   360→    required this.strokeWidth,
   361→  });
   362→
   363→  final List<Offset> points;
   364→  final Color color;
   365→  final double strokeWidth;
   366→
   367→  @override
   368→  void paint(Canvas canvas, Size size) {
   369→    if (points.length < 2) return;
   370→    final paint = Paint()
   371→      ..color = color
   372→      ..strokeWidth = strokeWidth
   373→      ..style = PaintingStyle.stroke
   374→      ..strokeCap = StrokeCap.round;
   375→
   376→    final path = Path()..moveTo(points.first.dx, points.first.dy);
   377→    for (var i = 1; i < points.length; i++) {
   378→      path.lineTo(points[i].dx, points[i].dy);
   379→    }
   380→    canvas.drawPath(path, paint);
   381→  }
   382→
   383→  @override
   384→  bool shouldRepaint(_ActiveStrokePainter oldDelegate) =>
   385→      points != oldDelegate.points;
   386→}
