   353→  void didUpdateWidget(StatefulWidget oldWidget) {
   354→    super.didUpdateWidget(oldWidget);
   355→    final old = oldWidget as OiTable<T>;
   356→    if (_widget.controller != old.controller) {
   357→      _disposeControllerIfOwned();
   358→      _initController();
   359→    }
   360→    // Sync totalRows for server-side pagination.
   361→    final total = _widget.totalRows ?? _widget.rows.length;
   362→    if (_ctrl.pagination.totalItems != total) {
   363→      _ctrl.pagination.setTotalItems(total);
   364→    }
   365→  }
   366→
   367→  @override
   368→  void didChangeDependencies() {
   369→    super.didChangeDependencies();
   370→    // Apply persisted settings once they load, but only when a driver is
   371→    // configured — without a driver, currentSettings is just defaultSettings
   372→    // and applying it would overwrite the external controller's own state.
   373→    if (settingsLoaded && settingsDriver != null) {
   374→      _ctrl.applySettings(currentSettings);
   375→    }
   376→  }
   377→
   378→  @override
   379→  void dispose() {
   380→    _scrollController
   381→      ..removeListener(_onScroll)
   382→      ..dispose();
   383→    _disposeControllerIfOwned();
   384→    super.dispose();
   385→  }
   386→
   387→  void _initController() {
   388→    if (_widget.controller != null) {
   389→      _ctrl = _widget.controller!;
   390→      _ownsController = false;
   391→      // Sync explicit totalRows into the external controller's pagination.
   392→      if (_widget.totalRows != null) {
   393→        _ctrl.pagination.setTotalItems(_widget.totalRows!);
   394→      }
   395→    } else {
   396→      final total = _widget.totalRows ?? _widget.rows.length;
   397→      _ctrl = OiTableController(totalRows: total);
   398→      _ownsController = true;
   399→    }
   400→    _ctrl.addListener(_onControllerChanged);
   401→  }
   402→
   403→  void _disposeControllerIfOwned() {
   404→    _ctrl.removeListener(_onControllerChanged);
   405→    if (_ownsController) _ctrl.dispose();
   406→  }
   407→
   408→  void _onControllerChanged() {
   409→    if (!mounted) return;
   410→    // Persist settings on every controller change (debounced by the mixin).
   411→    updateSettings(_ctrl.toSettings());
   412→    setState(() {});
   413→  }
   414→
   415→  void _onScroll() {
   416→    if (!mounted) return;
   417→    if (_widget.paginationMode != OiTablePaginationMode.infinite) return;
   418→    if (_loadingMore) return;
   419→    if (_scrollController.position.pixels >=
   420→        _scrollController.position.maxScrollExtent - 100) {
   421→      _triggerLoadMore();
   422→    }
   423→  }
   424→
   425→  Future<void> _triggerLoadMore() async {
   426→    if (_loadingMore || _widget.onLoadMore == null) return;
   427→    setState(() => _loadingMore = true);
   428→    try {
   429→      await _widget.onLoadMore!();
   430→    } finally {
   431→      if (mounted) setState(() => _loadingMore = false);
   432→    }
   433→  }
