   435→  // ── Data helpers ───────────────────────────────────────────────────────────
   436→
   437→  /// Returns the effective column list respecting [OiTableController.columnOrder]
   438→  /// and [OiTableController.columnVisibility].
   439→  List<OiTableColumn<T>> get _visibleColumns {
   440→    final order = _ctrl.columnOrder;
   441→    final List<OiTableColumn<T>> cols;
   442→    if (order.isEmpty) {
   443→      cols = List<OiTableColumn<T>>.from(_widget.columns);
   444→    } else {
   445→      final byId = {for (final c in _widget.columns) c.id: c};
   446→      cols = [
   447→        for (final id in order)
   448→          if (byId.containsKey(id)) byId[id]!,
   449→        // Append any columns not mentioned in order.
   450→        for (final c in _widget.columns)
   451→          if (!order.contains(c.id)) c,
   452→      ];
   453→    }
   454→    return cols
   455→        .where((c) => (_ctrl.columnVisibility[c.id] ?? true) && !c.hidden)
   456→        .toList();
   457→  }
   458→
   459→  /// Applies client-side filter to [rows].
   460→  List<T> get _filteredRows {
   461→    if (_widget.serverSideFilter || _ctrl.activeFilters.isEmpty) {
   462→      return _widget.rows;
   463→    }
   464→    return _widget.rows.where((row) {
   465→      for (final entry in _ctrl.activeFilters.entries) {
   466→        final col = _columnById(entry.key);
   467→        if (col == null) continue;
   468→        final value = col.valueGetter?.call(row) ?? '';
   469→        if (!value.toLowerCase().contains(entry.value.toLowerCase())) {
   470→          return false;
   471→        }
   472→      }
   473→      return true;
   474→    }).toList();
   475→  }
   476→
   477→  /// Applies client-side sort to [rows].
   478→  List<T> _sortedRows(List<T> rows) {
   479→    final colId = _ctrl.sortColumnId;
   480→    if (_widget.serverSideSort || colId == null) return rows;
   481→    final col = _columnById(colId);
   482→    if (col == null) return rows;
   483→    final sorted = List<T>.from(rows)
   484→      ..sort((a, b) {
   485→        final cmp = col.comparator != null
   486→            ? col.comparator!(a, b)
   487→            : (col.valueGetter?.call(a) ?? '').compareTo(
   488→                col.valueGetter?.call(b) ?? '',
   489→              );
   490→        return _ctrl.sortAscending ? cmp : -cmp;
   491→      });
   492→    return sorted;
   493→  }
   494→
   495→  /// Applies pagination to [rows] in [OiTablePaginationMode.pages] mode.
   496→  List<T> _paginatedRows(List<T> rows) {
   497→    if (_widget.paginationMode != OiTablePaginationMode.pages) return rows;
   498→    final start = _ctrl.pagination.startIndex;
   499→    final end = math.min(_ctrl.pagination.endIndex, rows.length);
   500→    if (start >= rows.length) return const [];
   501→    return rows.sublist(start, end);
   502→  }
   503→
   504→  /// Returns [rows] after filter → sort → paginate pipeline.
   505→  List<T> get _displayRows {
   506→    final filtered = _filteredRows;
   507→    final sorted = _sortedRows(filtered);
   508→    // Update pagination total after filter — only for fully client-side tables
   509→    // that do not supply an explicit totalRows override.
   510→    if (!_widget.serverSideSort &&
   511→        !_widget.serverSideFilter &&
   512→        _widget.totalRows == null &&
   513→        _widget.paginationMode == OiTablePaginationMode.pages) {
   514→      WidgetsBinding.instance.addPostFrameCallback((_) {
   515→        if (!mounted) return;
   516→        _ctrl.pagination.setTotalItems(sorted.length);
   517→      });
   518→    }
   519→    return _paginatedRows(sorted);
   520→  }
   521→
   522→  OiTableColumn<T>? _columnById(String id) {
   523→    for (final c in _widget.columns) {
   524→      if (c.id == id) return c;
   525→    }
   526→    return null;
   527→  }
