   529→  // ── Interaction handlers ──────────────────────────────────────────────────
   530→
   531→  void _handleHeaderTap(OiTableColumn<T> col) {
   532→    if (!col.sortable) return;
   533→    _ctrl.sortBy(col.id);
   534→    _widget.onSort?.call(col.id, ascending: _ctrl.sortAscending);
   535→  }
   536→
   537→  void _handleRowTap(T row, int index) {
   538→    if (_widget.selectable) {
   539→      _ctrl.selectRow(index, multi: _widget.multiSelect);
   540→      _widget.onSelectionChanged?.call(_ctrl.selectedRows.toList()..sort());
   541→    }
   542→    _widget.onRowTap?.call(row, index);
   543→  }
   544→
   545→  void _handleRowDoubleTap(T row, int index) {
   546→    _widget.onRowDoubleTap?.call(row, index);
   547→  }
   548→
   549→  void _copySelectedRows() {
   550→    if (!_widget.copyable) return;
   551→    final cols = _visibleColumns;
   552→    final buffer = StringBuffer();
   553→    for (final idx in _ctrl.selectedRows.toList()..sort()) {
   554→      if (idx < _widget.rows.length) {
   555→        final row = _widget.rows[idx];
   556→        final cells = cols
   557→            .map((c) => c.valueGetter?.call(row) ?? '')
   558→            .join('\t');
   559→        buffer.writeln(cells);
   560→      }
   561→    }
   562→    Clipboard.setData(ClipboardData(text: buffer.toString()));
   563→  }
