   649→  Widget _buildColumnHeader(OiTableColumn<T> col) {
   650→    final isSorted = _ctrl.sortColumnId == col.id;
   651→    final sortIcon = isSorted ? (_ctrl.sortAscending ? ' ▲' : ' ▼') : '';
   652→    final width = _ctrl.columnWidths[col.id] ?? col.width;
