   654→      padding: const EdgeInsets.symmetric(horizontal: 8),
   655→      child: Row(
   656→        mainAxisSize: MainAxisSize.min,
   657→        children: [
   658→          Flexible(
   659→            child: Text(
   660→              '${col.header}$sortIcon',
   661→              textAlign: col.textAlign,
   662→              overflow: TextOverflow.ellipsis,
   663→            ),
   664→          ),
   665→          if (col.resizable)
