   667→              onResize: (delta) {
   668→                final current = _ctrl.columnWidths[col.id] ?? col.width ?? 120;
   669→                final next = (current + delta).clamp(
   670→                  col.minWidth,
   671→                  col.maxWidth,
   672→                );
   673→                _ctrl.setColumnWidth(col.id, next);
   674→              },
   675→            ),
   676→        ],
   677→      ),
   678→    );
   679→    // When no explicit width is set, use a flexible default so the cell
