   686→        width: resolvedWidth,
   687→        height: _effectiveRowHeight,
   688→        child: innerContent,
   689→      ),
   690→    );
   691→    var header = headerChild as Widget;
   692→    if (col.filterable) {
   693→      header = Column(
   694→        mainAxisSize: MainAxisSize.min,
   695→        children: [header, _buildFilterInput(col)],
