   722→  Widget _buildBody() {
   723→    if (_widget.loading) return _buildLoadingState();
   724→    final rows = _displayRows;
   725→    if (rows.isEmpty) {
   726→      return _widget.emptyState ?? _buildDefaultEmptyState();
   727→    }
   728→    if (_widget.groupBy != null || _ctrl.groupByColumnId != null) {
   729→      return _buildGroupedBody(rows);
   730→    }
   731→    return _buildFlatBody(rows);
