   742→  Widget _buildFlatBody(List<T> rows) {
   743→    return ListView.builder(
   744→      controller: _scrollController,
   745→      itemCount: rows.length + (_loadingMore ? 1 : 0),
   746→      itemBuilder: (ctx, int i) {
   747→        if (i == rows.length) {
   748→          return const Center(
   749→            key: Key('oi_table_load_more_indicator'),
   750→            child: _OiTableSpinner(),
   751→          );
   752→        }
   753→        return _buildRow(rows[i], i);
   754→      },
   755→    );
   756→  }
   757→
   758→  Widget _buildGroupedBody(List<T> rows) {
   759→    final groupColId =
   760→        _ctrl.groupByColumnId ?? _widget.groupBy ?? _widget.columns.first.id;
   761→    final col = _columnById(groupColId);
   762→    // Group rows by their valueGetter value.
   763→    final groups = <String, List<T>>{};
   764→    for (final row in rows) {
   765→      final key = col?.valueGetter?.call(row) ?? '';
   766→      groups.putIfAbsent(key, () => []).add(row);
   767→    }
   768→    final items = <Widget>[];
   769→    for (final entry in groups.entries) {
   770→      final groupKey = entry.key;
   771→      final groupRows = entry.value;
   772→      final expanded = _ctrl.expandedGroups.contains(groupKey);
   773→      // Group header.
   774→      final header = _widget.groupHeaderBuilder != null
   775→          ? _widget.groupHeaderBuilder!(context, groupKey, groupRows)
   776→          : _buildDefaultGroupHeader(groupKey, groupRows.length, expanded);
   777→      items.add(
   778→        GestureDetector(
   779→          key: ValueKey('group_$groupKey'),
   780→          onTap: () => _ctrl.toggleGroup(groupKey),
   781→          child: header,
   782→        ),
   783→      );
   784→      if (expanded) {
   785→        for (var i = 0; i < groupRows.length; i++) {
   786→          items.add(_buildRow(groupRows[i], i));
   787→        }
   788→      }
   789→    }
   790→    return ListView(controller: _scrollController, children: items);
   791→  }
