   810→  Widget _buildRow(T row, int index, {Key? key}) {
   811→    final isSelected = _ctrl.selectedRows.contains(index);
   812→    final isEven = index.isEven;
   813→    Color? bg;
   814→    if (isSelected) {
   815→      bg = const Color(0xFFDBEAFE);
   816→    } else if (_widget.striped && isEven) {
   817→      bg = const Color(0xFFF8FAFC);
   818→    }
   819→    final rowContent = Row(
   820→      children: [
   821→        if (_widget.selectable)
   822→          SizedBox(
   823→            width: 40,
   824→            height: _effectiveRowHeight,
   825→            child: Center(child: Text(isSelected ? '☑' : '☐')),
   826→          ),
   827→        for (final col in _visibleColumns) _buildCell(row, index, col),
   828→      ],
   829→    );
   830→    return GestureDetector(
   831→      key: key ?? ValueKey('row_$index'),
   832→      behavior: HitTestBehavior.opaque,
   833→      onTap: () => _handleRowTap(row, index),
   834→      onDoubleTap: () => _handleRowDoubleTap(row, index),
   835→      child: bg != null ? ColoredBox(color: bg, child: rowContent) : rowContent,
   836→    );
