   839→  Widget _buildCell(T row, int rowIndex, OiTableColumn<T> col) {
   840→    final width = _ctrl.columnWidths[col.id] ?? col.width;
   841→    Widget content;
   842→    if (col.cellBuilder != null) {
   843→      content = col.cellBuilder!(context, row, rowIndex);
   844→    } else {
   845→      final text = col.valueGetter?.call(row) ?? '';
   846→      content = Text(text, textAlign: col.textAlign);
   847→    }
   848→    if (_widget.onCellChanged != null) {
   849→      content = _CellFrame<T>(
   850→        row: row,
   851→        rowIndex: rowIndex,
   852→        columnId: col.id,
   853→        child: content,
   854→        onChanged: (value) =>
   855→            _widget.onCellChanged!(row, rowIndex, col.id, value),
   856→      );
   857→    }
   858→    final resolvedWidth =
   859→        width ?? col.minWidth.clamp(col.minWidth, col.maxWidth);
   860→    return SizedBox(
   861→      width: resolvedWidth,
   862→      height: _effectiveRowHeight,
   863→      child: Padding(
   864→        padding: const EdgeInsets.symmetric(horizontal: 8),
   865→        child: Align(
   866→          alignment: _alignmentFromTextAlign(col.textAlign),
   867→          child: content,
   868→        ),
   869→      ),
   870→    );
   871→  }
