   919→// ── _CellFrame ────────────────────────────────────────────────────────────────
   920→
   921→/// Internal widget that wraps a table cell and handles the transition between
   922→/// display mode and edit mode.
   923→class _CellFrame<T> extends StatefulWidget {
   924→  const _CellFrame({
   925→    required this.row,
   926→    required this.rowIndex,
   927→    required this.columnId,
   928→    required this.child,
   929→    required this.onChanged,
   930→    super.key,
   931→  });
   932→
   933→  final T row;
   934→  final int rowIndex;
   935→  final String columnId;
   936→  final Widget child;
   937→  final void Function(dynamic value) onChanged;
   938→
   939→  @override
   940→  State<_CellFrame<T>> createState() => _CellFrameState<T>();
   941→}
   942→
   943→class _CellFrameState<T> extends State<_CellFrame<T>> {
   944→  bool _editing = false;
   945→  final TextEditingController _textCtrl = TextEditingController();
   946→
   947→  @override
   948→  void dispose() {
   949→    _textCtrl.dispose();
   950→    super.dispose();
   951→  }
   952→
   953→  void _startEdit() {
   954→    setState(() => _editing = true);
   955→  }
   956→
   957→  void _commit() {
