     3→/// Describes a remote user's cursor position on a shared surface.
     4→///
     5→/// {@category Composites}
     6→class OiRemoteCursor {
     7→  /// Creates an [OiRemoteCursor].
     8→  const OiRemoteCursor({
     9→    required this.userId,
    10→    required this.name,
    11→    required this.color,
    12→    required this.position,
    13→    required this.lastMoved,
    14→  });
    15→
    16→  /// A unique identifier for the remote user.
    17→  final String userId;
    18→
    19→  /// The display name of the remote user.
    20→  final String name;
    21→
    22→  /// The color used to render this user's cursor.
    23→  final Color color;
    24→
    25→  /// The cursor position in logical pixels relative to the shared surface.
    26→  final Offset position;
    27→
    28→  /// The time the cursor was last moved. Used to fade out stale cursors.
    29→  final DateTime lastMoved;
    30→}
    31→
    32→/// Overlays remote users' cursors on top of a shared [child] surface.
    33→///
    34→/// Each cursor is drawn at the position specified by [OiRemoteCursor.position]
    35→/// with the user's assigned [OiRemoteCursor.color]. User names are shown next
    36→/// to the cursor when [showNames] is `true`.
    37→///
    38→/// Cursors that have not been moved for longer than [fadeAfter] are rendered
    39→/// at reduced opacity to indicate inactivity.
    40→///
    41→/// {@category Composites}
    42→class OiCursorPresence extends StatelessWidget {
    43→  /// Creates an [OiCursorPresence].
    44→  const OiCursorPresence({
    45→    required this.child,
    46→    required this.cursors,
    47→    super.key,
    48→    this.showNames = true,
    49→    this.fadeAfter = const Duration(seconds: 5),
    50→  });
    51→
    52→  /// The shared surface widget over which cursors are drawn.
    53→  final Widget child;
    54→
    55→  /// The list of remote cursors to render.
    56→  final List<OiRemoteCursor> cursors;
    57→
    58→  /// Whether to show the user's name next to their cursor.
    59→  final bool showNames;
    60→
    61→  /// Cursors inactive for longer than this duration are rendered at reduced
    62→  /// opacity. Defaults to 5 seconds.
    63→  final Duration fadeAfter;
    64→
    65→  @override
    66→  Widget build(BuildContext context) {
    67→    final now = DateTime.now();
    68→
    69→    return Stack(
    70→      children: [
    71→        Positioned.fill(child: child),
    72→        ...cursors.map((cursor) {
    73→          final elapsed = now.difference(cursor.lastMoved);
    74→          final isStale = elapsed > fadeAfter;
    75→          final opacity = isStale ? 0.3 : 1.0;
    76→
    77→          return Positioned(
    78→            left: cursor.position.dx,
    79→            top: cursor.position.dy,
    80→            child: Opacity(
    81→              opacity: opacity,
    82→              child: _CursorWidget(cursor: cursor, showName: showNames),
    83→            ),
    84→          );
    85→        }),
    86→      ],
    87→    );
    88→  }
    89→}
    90→
    91→class _CursorWidget extends StatelessWidget {
    92→  const _CursorWidget({required this.cursor, required this.showName});
    93→
    94→  final OiRemoteCursor cursor;
    95→  final bool showName;
    96→
    97→  @override
    98→  Widget build(BuildContext context) {
    99→    return Column(
   100→      mainAxisSize: MainAxisSize.min,
   101→      crossAxisAlignment: CrossAxisAlignment.start,
   102→      children: [
   103→        CustomPaint(
   104→          size: const Size(12, 18),
   105→          painter: _CursorPainter(color: cursor.color),
   106→        ),
   107→        if (showName)
   108→          Container(
   109→            margin: const EdgeInsets.only(left: 8),
   110→            padding: const EdgeInsets.symmetric(horizontal: 4, vertical: 2),
   111→            decoration: BoxDecoration(
   112→              color: cursor.color,
   113→              borderRadius: BorderRadius.circular(4),
   114→            ),
   115→            child: Text(
   116→              cursor.name,
   117→              style: const TextStyle(
   118→                color: Color(0xFFFFFFFF),
   119→                fontSize: 11,
   120→                fontWeight: FontWeight.w500,
   121→                height: 1.2,
   122→              ),
   123→            ),
   124→          ),
   125→      ],
   126→    );
   127→  }
   128→}
   129→
   130→class _CursorPainter extends CustomPainter {
   131→  _CursorPainter({required this.color});
   132→
   133→  final Color color;
   134→
   135→  @override
   136→  void paint(Canvas canvas, Size size) {
   137→    final paint = Paint()..color = color;
   138→    final path = Path()
   139→      ..moveTo(0, 0)
   140→      ..lineTo(0, size.height)
   141→      ..lineTo(size.width * 0.7, size.height * 0.65)
   142→      ..close();
   143→    canvas.drawPath(path, paint);
   144→  }
   145→
   146→  @override
   147→  bool shouldRepaint(_CursorPainter oldDelegate) => color != oldDelegate.color;
   148→}
