     1→import 'package:flutter/physics.dart';
     2→import 'package:flutter/widgets.dart';
     3→
     4→/// A widget that drives a [builder] with a spring-physics animation toward a
     5→/// target [value].
     6→///
     7→/// When [value] changes the widget uses a [SpringSimulation] to animate from
     8→/// the current position to the new target, producing natural-feeling motion
     9→/// with configurable [stiffness], [damping], and [mass].
    10→///
    11→/// The [builder] is called on every frame with the current animated value and
    12→/// the optional [child] passthrough (which is not rebuilt on every frame,
    13→/// improving performance for expensive sub-trees).
    14→///
    15→/// ```dart
    16→/// OiSpring(
    17→///   value: _expanded ? 1.0 : 0.0,
    18→///   builder: (context, v, child) => Opacity(opacity: v, child: child),
    19→///   child: const ExpensiveWidget(),
    20→/// )
    21→/// ```
    22→///
    23→/// {@category Primitives}
    24→class OiSpring extends StatefulWidget {
    25→  /// Creates an [OiSpring].
    26→  const OiSpring({
    27→    required this.value,
    28→    required this.builder,
    29→    this.child,
    30→    this.stiffness = 300.0,
    31→    this.damping = 30.0,
    32→    this.mass = 1.0,
    33→    super.key,
    34→  });
    35→
    36→  /// Target value (typically 0.0 to 1.0).
    37→  ///
    38→  /// When this changes the spring animates from the current position toward
    39→  /// the new target.
    40→  final double value;
    41→
    42→  /// Builder that receives the current animated value on every frame.
    43→  ///
    44→  /// The optional [child] argument is the widget passed to [OiSpring.child],
    45→  /// which is not rebuilt each frame.
    46→  final Widget Function(BuildContext context, double value, Widget? child)
    47→  builder;
    48→
    49→  /// Optional child passed through to [builder] without being rebuilt on
    50→  /// every animation frame.
    51→  final Widget? child;
    52→
    53→  /// Spring stiffness. Higher values produce a faster, bouncier spring.
    54→  ///
    55→  /// Defaults to 300.0.
    56→  final double stiffness;
    57→
    58→  /// Spring damping. Higher values reduce oscillation.
    59→  ///
    60→  /// Defaults to 30.0.
    61→  final double damping;
    62→
    63→  /// Spring mass. Higher values produce slower, heavier motion.
    64→  ///
    65→  /// Defaults to 1.0.
    66→  final double mass;
    67→
    68→  @override
    69→  State<OiSpring> createState() => _OiSpringState();
    70→}
    71→
    72→class _OiSpringState extends State<OiSpring>
    73→    with SingleTickerProviderStateMixin {
    74→  late AnimationController _controller;
    75→
    76→  @override
    77→  void initState() {
    78→    super.initState();
    79→    _controller = AnimationController.unbounded(vsync: this)
    80→      ..value = widget.value;
    81→  }
    82→
    83→  @override
    84→  void didUpdateWidget(OiSpring oldWidget) {
    85→    super.didUpdateWidget(oldWidget);
    86→    if (oldWidget.value != widget.value ||
    87→        oldWidget.stiffness != widget.stiffness ||
    88→        oldWidget.damping != widget.damping ||
    89→        oldWidget.mass != widget.mass) {
    90→      _runSpring(
    91→        from: _controller.value,
    92→        to: widget.value,
    93→        velocity: _controller.velocity,
    94→      );
    95→    }
    96→  }
    97→
    98→  void _runSpring({
    99→    required double from,
   100→    required double to,
   101→    double velocity = 0,
   102→  }) {
   103→    final desc = SpringDescription(
   104→      mass: widget.mass,
   105→      stiffness: widget.stiffness,
   106→      damping: widget.damping,
   107→    );
   108→    final sim = SpringSimulation(desc, from, to, velocity);
   109→    _controller.animateWith(sim);
   110→  }
   111→
   112→  @override
   113→  void dispose() {
   114→    _controller.dispose();
   115→    super.dispose();
   116→  }
   117→
   118→  @override
   119→  Widget build(BuildContext context) {
   120→    return AnimatedBuilder(
   121→      animation: _controller,
   122→      builder: (context, child) =>
   123→          widget.builder(context, _controller.value, child),
   124→      child: widget.child,
   125→    );
   126→  }
   127→}
