     5→/// Animates a list of [children] in sequence, each one starting after a
     6→/// [staggerDelay] offset from the previous.
     7→///
     8→/// A single [AnimationController] drives all children. Each child's visible
     9→/// range is mapped to an [Interval] so that they appear one after another.
    10→/// The transition style is controlled by [transition].
    11→///
    12→/// When [autoPlay] is true (the default) the stagger animation starts
    13→/// automatically on mount. Set it to false and call [OiStaggerController.play]
    14→/// to trigger the animation externally.
    15→///
    16→/// Respects `MediaQuery.disableAnimations`: when the user has requested reduced
    17→/// motion all children are shown immediately without animation.
    18→///
    19→/// ```dart
    20→/// OiStagger(
    21→///   staggerDelay: const Duration(milliseconds: 80),
    22→///   children: items.map((t) => Text(t)).toList(),
    23→/// )
    24→/// ```
    25→///
    26→/// {@category Primitives}
    27→class OiStagger extends StatefulWidget {
    28→  /// Creates an [OiStagger].
    29→  const OiStagger({
    30→    required this.children,
    31→    this.staggerDelay = const Duration(milliseconds: 80),
    32→    this.duration = const Duration(milliseconds: 300),
    33→    this.transition = OiTransition.fade,
    34→    this.autoPlay = true,
    35→    super.key,
    36→  });
    37→
    38→  /// The children to animate in sequence.
    39→  final List<Widget> children;
    40→
    41→  /// Delay between each child's animation start.
    42→  final Duration staggerDelay;
    43→
    44→  /// Duration of each individual child's animation.
    45→  final Duration duration;
    46→
    47→  /// The transition to apply to each child.
    48→  final OiTransition transition;
    49→
