    59→/// State for [OiStagger]. Exposed so that tests can call [play] directly.
    60→///
    61→/// {@category Primitives}
    62→class OiStaggerState extends State<OiStagger>
    63→    with SingleTickerProviderStateMixin {
    64→  late AnimationController _controller;
    65→
    66→  @override
    67→  void initState() {
    68→    super.initState();
    69→    final totalMs = _totalDuration().inMilliseconds;
    70→    _controller = AnimationController(
    71→      vsync: this,
    72→      duration: Duration(milliseconds: totalMs),
    73→    );
    74→    if (widget.autoPlay) {
    75→      // Defer until after the first frame so the context is fully available.
    76→      WidgetsBinding.instance.addPostFrameCallback((_) {
    77→        if (mounted) play();
    78→      });
    79→    }
    80→  }
    81→
    82→  @override
    83→  void didChangeDependencies() {
    84→    super.didChangeDependencies();
    85→    _controller.duration = _totalDuration();
    86→  }
    87→
    88→  @override
    89→  void dispose() {
    90→    _controller.dispose();
    91→    super.dispose();
    92→  }
    93→
    94→  /// Total controller duration: last child offset + one child duration.
    95→  Duration _totalDuration() {
    96→    final n = widget.children.length;
    97→    if (n == 0) return widget.duration;
    98→    final staggerMs = widget.staggerDelay.inMilliseconds * (n - 1);
    99→    return Duration(milliseconds: staggerMs + widget.duration.inMilliseconds);
   100→  }
   101→
   102→  /// Starts the stagger animation from the beginning.
   103→  void play() {
   104→    if (!mounted) return;
   105→    final reduced = OiA11y.reducedMotion(context);
   106→    if (reduced) {
   107→      _controller.value = 1.0;
   108→    } else {
   109→      _controller.forward(from: 0);
   110→    }
   111→  }
   112→
   113→  Widget _applyTransition(
   114→    OiTransition transition,
   115→    Animation<double> animation,
   116→    Widget child,
   117→  ) {
   118→    switch (transition) {
   119→      case OiTransition.none:
   120→        return child;
   121→      case OiTransition.fade:
   122→        return FadeTransition(opacity: animation, child: child);
   123→      case OiTransition.fadeScale:
   124→        return FadeTransition(
   125→          opacity: animation,
   126→          child: ScaleTransition(
   127→            scale: Tween<double>(begin: 0.9, end: 1).animate(animation),
   128→            child: child,
   129→          ),
   130→        );
   131→      case OiTransition.slideUp:
   132→        return FadeTransition(
   133→          opacity: animation,
   134→          child: SlideTransition(
   135→            position: Tween<Offset>(
   136→              begin: const Offset(0, 0.1),
   137→              end: Offset.zero,
   138→            ).animate(animation),
   139→            child: child,
   140→          ),
   141→        );
   142→      case OiTransition.slideDown:
   143→        return FadeTransition(
   144→          opacity: animation,
   145→          child: SlideTransition(
   146→            position: Tween<Offset>(
   147→              begin: const Offset(0, -0.1),
   148→              end: Offset.zero,
   149→            ).animate(animation),
   150→            child: child,
   151→          ),
   152→        );
   153→      case OiTransition.slideLeft:
   154→        return FadeTransition(
   155→          opacity: animation,
   156→          child: SlideTransition(
   157→            position: Tween<Offset>(
   158→              begin: const Offset(0.1, 0),
   159→              end: Offset.zero,
   160→            ).animate(animation),
   161→            child: child,
   162→          ),
   163→        );
   164→      case OiTransition.slideRight:
   165→        return FadeTransition(
   166→          opacity: animation,
   167→          child: SlideTransition(
   168→            position: Tween<Offset>(
   169→              begin: const Offset(-0.1, 0),
   170→              end: Offset.zero,
   171→            ).animate(animation),
   172→            child: child,
   173→          ),
   174→        );
   175→    }
   176→  }
   177→
   178→  @override
   179→  Widget build(BuildContext context) {
   180→    final reduced = OiA11y.reducedMotion(context);
   181→    final n = widget.children.length;
   182→    if (n == 0) return const SizedBox.shrink();
   183→
   184→    final totalMs = _totalDuration().inMilliseconds.toDouble();
   185→
   186→    return AnimatedBuilder(
   187→      animation: _controller,
   188→      builder: (context, _) {
   189→        return Column(
   190→          mainAxisSize: MainAxisSize.min,
   191→          crossAxisAlignment: CrossAxisAlignment.start,
   192→          children: List.generate(n, (i) {
   193→            if (reduced) {
   194→              return widget.children[i];
   195→            }
   196→            final startMs = widget.staggerDelay.inMilliseconds * i;
   197→            final endMs = startMs + widget.duration.inMilliseconds;
   198→            final start = totalMs > 0 ? startMs / totalMs : 0.0;
   199→            final end = totalMs > 0 ? endMs / totalMs : 1.0;
   200→            final interval = CurvedAnimation(
   201→              parent: _controller,
   202→              curve: Interval(start, end, curve: Curves.easeOut),
   203→            );
   204→            return _applyTransition(
   205→              widget.transition,
   206→              interval,
   207→              widget.children[i],
   208→            );
   209→          }),
   210→        );
   211→      },
   212→    );
   213→  }
   214→}
