     4→/// Applies a looping opacity and/or scale pulse animation to [child].
     5→///
     6→/// When [active] is true an [AnimationController] repeats in reverse,
     7→/// driving [Opacity] and [Transform.scale] between their min and max values.
     8→/// When [active] is false [child] is rendered without any wrapping.
     9→///
    10→/// Respects `MediaQuery.disableAnimations`: when the user has requested
    11→/// reduced motion the animation is skipped and [child] is shown at full
    12→/// opacity and scale.
    13→///
    14→/// ```dart
    15→/// OiPulse(
    16→///   active: isLoading,
    17→///   minOpacity: 0.3,
    18→///   child: Icon(Icons.circle),
    19→/// )
    20→/// ```
    21→///
    22→/// {@category Primitives}
    23→class OiPulse extends StatefulWidget {
    24→  /// Creates an [OiPulse].
    25→  const OiPulse({
    26→    required this.child,
    27→    this.active = true,
    28→    this.minOpacity = 0.4,
    29→    this.maxOpacity = 1.0,
    30→    this.minScale = 1.0,
    31→    this.maxScale = 1.0,
    32→    this.duration,
    33→    super.key,
    34→  });
    35→
    36→  /// The child to pulse.
    37→  final Widget child;
    38→
    39→  /// Whether the pulse animation is active.
    40→  ///
    41→  /// When false, [child] is rendered directly without any animation wrapper.
    42→  final bool active;
    43→
    44→  /// Minimum opacity during the pulse. Defaults to 0.4.
    45→  final double minOpacity;
    46→
    47→  /// Maximum opacity during the pulse. Defaults to 1.0.
    48→  final double maxOpacity;
    49→
    50→  /// Minimum scale during the pulse. Defaults to 1.0.
    51→  final double minScale;
    52→
    53→  /// Maximum scale during the pulse.
    54→  ///
    55→  /// Set above 1.0 to add a scale component to the pulse. Defaults to 1.0.
    56→  final double maxScale;
    57→
    58→  /// Duration of one full pulse cycle. Defaults to 1000 ms.
    59→  final Duration? duration;
    60→
    61→  @override
    62→  State<OiPulse> createState() => _OiPulseState();
    63→}
    64→
    65→class _OiPulseState extends State<OiPulse> with SingleTickerProviderStateMixin {
    66→  late AnimationController _controller;
    67→  late Animation<double> _opacityAnim;
    68→  late Animation<double> _scaleAnim;
    69→
    70→  @override
    71→  void initState() {
    72→    super.initState();
    73→    _controller = AnimationController(
    74→      vsync: this,
    75→      duration: widget.duration ?? const Duration(milliseconds: 1000),
    76→    );
    77→    _buildAnimations();
    78→    if (widget.active) {
    79→      _controller.repeat(reverse: true);
    80→    }
    81→  }
    82→
    83→  @override
    84→  void didChangeDependencies() {
    85→    super.didChangeDependencies();
    86→    _syncAnimation();
    87→  }
    88→
    89→  @override
    90→  void didUpdateWidget(OiPulse oldWidget) {
    91→    super.didUpdateWidget(oldWidget);
    92→    if (oldWidget.duration != widget.duration) {
    93→      _controller.duration =
    94→          widget.duration ?? const Duration(milliseconds: 1000);
    95→    }
    96→    if (oldWidget.minOpacity != widget.minOpacity ||
    97→        oldWidget.maxOpacity != widget.maxOpacity ||
    98→        oldWidget.minScale != widget.minScale ||
    99→        oldWidget.maxScale != widget.maxScale) {
   100→      _buildAnimations();
   101→    }
   102→    _syncAnimation();
   103→  }
   104→
   105→  void _buildAnimations() {
   106→    _opacityAnim = Tween<double>(
   107→      begin: widget.minOpacity,
   108→      end: widget.maxOpacity,
   109→    ).animate(_controller);
   110→    _scaleAnim = Tween<double>(
   111→      begin: widget.minScale,
   112→      end: widget.maxScale,
   113→    ).animate(_controller);
   114→  }
   115→
   116→  void _syncAnimation() {
   117→    final reduced = OiA11y.reducedMotion(context);
   118→    if (widget.active && !reduced) {
   119→      if (!_controller.isAnimating) _controller.repeat(reverse: true);
   120→    } else {
   121→      _controller.stop();
   122→    }
   123→  }
   124→
   125→  @override
   126→  void dispose() {
   127→    _controller.dispose();
   128→    super.dispose();
   129→  }
   130→
   131→  @override
   132→  Widget build(BuildContext context) {
   133→    if (!widget.active) return widget.child;
   134→
   135→    final reduced = OiA11y.reducedMotion(context);
   136→    if (reduced) return widget.child;
   137→
   138→    return AnimatedBuilder(
   139→      animation: _controller,
   140→      builder: (context, child) {
   141→        return Opacity(
   142→          opacity: _opacityAnim.value,
   143→          child: Transform.scale(scale: _scaleAnim.value, child: child),
   144→        );
   145→      },
   146→      child: widget.child,
   147→    );
   148→  }
   149→}
