     3→/// A widget that wraps its [child] with pinch-to-zoom and optional pan support.
     4→///
     5→/// Uses [GestureDetector] scale callbacks to track the current [_scale] and
     6→/// [_offset]. The transform is applied via [Transform] so the child renders at
     7→/// the correct scale and position. When [clipBehavior] is `true` overflow is
     8→/// hidden with a [ClipRect].
     9→///
    10→/// ```dart
    11→/// OiPinchZoom(
    12→///   minScale: 0.5,
    13→///   maxScale: 4.0,
    14→///   child: Image.asset('photo.png'),
    15→/// )
    16→/// ```
    17→///
    18→/// {@category Primitives}
    19→class OiPinchZoom extends StatefulWidget {
    20→  /// Creates an [OiPinchZoom].
    21→  const OiPinchZoom({
    22→    required this.child,
    23→    this.minScale = 0.5,
    24→    this.maxScale = 4.0,
    25→    this.initialScale = 1.0,
    26→    this.panEnabled = true,
    27→    this.onScaleChanged,
    28→    this.clipBehavior = true,
    29→    super.key,
    30→  });
    31→
    32→  /// The content to zoom.
    33→  final Widget child;
    34→
    35→  /// Minimum scale.
    36→  ///
    37→  /// Defaults to `0.5`.
    38→  final double minScale;
    39→
    40→  /// Maximum scale.
    41→  ///
    42→  /// Defaults to `4.0`.
    43→  final double maxScale;
    44→
    45→  /// Initial scale.
    46→  ///
    47→  /// Defaults to `1.0`.
    48→  final double initialScale;
    49→
    50→  /// Whether panning (translation) is enabled alongside zooming.
    51→  ///
    52→  /// Defaults to `true`.
    53→  final bool panEnabled;
    54→
    55→  /// Callback invoked with the new scale value whenever the scale changes.
    56→  final ValueChanged<double>? onScaleChanged;
    57→
    58→  /// Whether to clip content that overflows the original bounds.
    59→  ///
    60→  /// Defaults to `true`.
    61→  final bool clipBehavior;
    62→
    63→  @override
    64→  State<OiPinchZoom> createState() => _OiPinchZoomState();
    65→}
    66→
    67→class _OiPinchZoomState extends State<OiPinchZoom> {
    68→  late double _scale;
    69→  Offset _offset = Offset.zero;
    70→  late double _baseScale;
    71→
    72→  @override
    73→  void initState() {
    74→    super.initState();
    75→    _scale = widget.initialScale.clamp(widget.minScale, widget.maxScale);
    76→    _baseScale = _scale;
    77→  }
    78→
    79→  void _onScaleStart(ScaleStartDetails details) {
    80→    _baseScale = _scale;
    81→  }
    82→
    83→  void _onScaleUpdate(ScaleUpdateDetails details) {
    84→    setState(() {
    85→      final newScale = (_baseScale * details.scale).clamp(
    86→        widget.minScale,
    87→        widget.maxScale,
    88→      );
    89→      _scale = newScale;
    90→      if (widget.panEnabled) {
    91→        _offset += details.focalPointDelta;
    92→      }
    93→    });
    94→    widget.onScaleChanged?.call(_scale);
    95→  }
    96→
    97→  void _onScaleEnd(ScaleEndDetails details) {
    98→    // No post-gesture processing needed.
    99→  }
   100→
   101→  @override
   102→  Widget build(BuildContext context) {
   103→    Widget content = Transform(
   104→      transform: Matrix4.identity()
   105→        ..translateByDouble(_offset.dx, _offset.dy, 0, 1)
   106→        ..scaleByDouble(_scale, _scale, 1, 1),
   107→      alignment: Alignment.center,
   108→      child: widget.child,
   109→    );
   110→
   111→    if (widget.clipBehavior) {
   112→      content = ClipRect(child: content);
   113→    }
   114→
   115→    return GestureDetector(
   116→      onScaleStart: _onScaleStart,
   117→      onScaleUpdate: _onScaleUpdate,
   118→      onScaleEnd: _onScaleEnd,
   119→      child: content,
   120→    );
   121→  }
   122→}
