     3→/// A wrapper that adds infinite-scroll behaviour to any scrollable [child].
     4→///
     5→/// [OiInfiniteScroll] listens to scroll notifications from its [child]. When
     6→/// the scroll position approaches the bottom (within [threshold] pixels) and
     7→/// [moreAvailable] is `true`, [onLoadMore] is called. While the future is in flight
     8→/// a [loadingWidget] (or a default spinner) is shown at the bottom of the
     9→/// stack. Once the future resolves the loading indicator is removed.
    10→///
    11→/// ```dart
    12→/// OiInfiniteScroll(
    13→///   moreAvailable: _hasMore,
    14→///   onLoadMore: _fetchNextPage,
    15→///   child: ListView.builder(
    16→///     itemCount: items.length,
    17→///     itemBuilder: (_, i) => Text(items[i]),
    18→///   ),
    19→/// )
    20→/// ```
    21→///
    22→/// {@category Primitives}
    23→class OiInfiniteScroll extends StatefulWidget {
    24→  /// Creates an [OiInfiniteScroll].
    25→  const OiInfiniteScroll({
    26→    required this.moreAvailable,
    27→    required this.onLoadMore,
    28→    required this.child,
    29→    this.loadingWidget,
    30→    this.threshold = 200,
    31→    super.key,
    32→  });
    33→
    34→  /// Whether more items can be loaded.
    35→  ///
    36→  /// When `false`, [onLoadMore] will not be called even if the user scrolls
    37→  /// to the bottom.
    38→  final bool moreAvailable;
    39→
    40→  /// Called when the user scrolls within [threshold] pixels of the bottom.
    41→  ///
    42→  /// The returned future is awaited; [loadingWidget] is shown for its
    43→  /// duration.
    44→  final Future<void> Function() onLoadMore;
    45→
    46→  /// Widget to display while [onLoadMore] is in progress.
    47→  ///
    48→  /// Defaults to a small animated spinner when null.
    49→  final Widget? loadingWidget;
    50→
    51→  /// Distance in pixels from the bottom of the scroll content that triggers
    52→  /// a load. Defaults to 200.
    53→  final double threshold;
    54→
    55→  /// The scrollable content.
    56→  ///
    57→  /// Typically a [ListView], [GridView], or [CustomScrollView].
    58→  final Widget child;
    59→
    60→  @override
    61→  State<OiInfiniteScroll> createState() => _OiInfiniteScrollState();
    62→}
    63→
    64→class _OiInfiniteScrollState extends State<OiInfiniteScroll> {
    65→  bool _isLoading = false;
    66→
    67→  bool _onNotification(ScrollNotification notification) {
    68→    if (!widget.moreAvailable || _isLoading) return false;
    69→
    70→    final metrics = notification.metrics;
    71→    if (metrics.pixels >= metrics.maxScrollExtent - widget.threshold) {
    72→      _loadMore();
    73→    }
    74→    return false;
    75→  }
    76→
    77→  Future<void> _loadMore() async {
    78→    if (_isLoading) return;
    79→    setState(() => _isLoading = true);
    80→    try {
    81→      await widget.onLoadMore();
    82→    } finally {
    83→      if (mounted) setState(() => _isLoading = false);
    84→    }
    85→  }
    86→
    87→  @override
    88→  Widget build(BuildContext context) {
    89→    return NotificationListener<ScrollNotification>(
    90→      onNotification: _onNotification,
    91→      child: Stack(
    92→        alignment: Alignment.bottomCenter,
    93→        children: [
    94→          widget.child,
    95→          if (_isLoading)
    96→            Positioned(
    97→              bottom: 16,
    98→              child:
    99→                  widget.loadingWidget ??
   100→                  const _InfiniteScrollSpinner(
   101→                    key: ValueKey('oi_infinite_scroll_spinner'),
   102→                  ),
   103→            ),
   104→        ],
   105→      ),
   106→    );
   107→  }
   108→}
