   114→  @override
   115→  State<_InfiniteScrollSpinner> createState() => _InfiniteScrollSpinnerState();
   116→}
   117→
   118→class _InfiniteScrollSpinnerState extends State<_InfiniteScrollSpinner>
   119→    with SingleTickerProviderStateMixin {
   120→  late final AnimationController _controller;
   121→
   122→  @override
   123→  void initState() {
   124→    super.initState();
   125→    _controller = AnimationController(
   126→      vsync: this,
   127→      duration: const Duration(milliseconds: 800),
   128→    )..repeat();
   129→  }
   130→
   131→  @override
   132→  void dispose() {
   133→    _controller.dispose();
   134→    super.dispose();
   135→  }
   136→
   137→  @override
   138→  Widget build(BuildContext context) {
   139→    return RotationTransition(
   140→      turns: _controller,
   141→      child: const SizedBox(
   142→        width: 24,
   143→        height: 24,
   144→        child: CustomPaint(painter: _SpinnerPainter()),
   145→      ),
   146→    );
   147→  }
   148→}
